import { Injectable, signal } from '@angular/core';

export type AiTone = 'STANDARD' | 'CALM';
export type WidgetId = 'INTEL' | 'MARKET' | 'SIGNALS' | null;
export type DataSourceMode = 'SIMULATION' | 'LIVE' | 'CUSTOM';
export type RefreshRate = 'AGGRESSIVE' | 'STANDARD' | 'SAFE'; // 30s, 60s, 120s

@Injectable({
  providedIn: 'root'
})
export class UserPrefsService {
  // Cognitive Settings
  readonly reducedMotion = signal<boolean>(false);
  readonly aiTone = signal<AiTone>('STANDARD');

  // Data Settings
  readonly dataSourceMode = signal<DataSourceMode>('SIMULATION');
  readonly refreshRate = signal<RefreshRate>('STANDARD');
  readonly customApiUrl = signal<string>(''); // User defined endpoint

  // Layout State (Focus Mode)
  readonly focusedWidget = signal<WidgetId>(null);

  toggleMotion() {
    this.reducedMotion.update(v => !v);
  }

  setTone(tone: AiTone) {
    this.aiTone.set(tone);
  }

  setDataSourceMode(mode: DataSourceMode) {
    this.dataSourceMode.set(mode);
  }

  setRefreshRate(rate: RefreshRate) {
    this.refreshRate.set(rate);
  }

  setCustomApiUrl(url: string) {
    this.customApiUrl.set(url);
  }

  setFocus(widgetId: WidgetId) {
    // If clicking the already focused widget, un-focus it (toggle behavior)
    if (this.focusedWidget() === widgetId) {
      this.focusedWidget.set(null);
    } else {
      this.focusedWidget.set(widgetId);
    }
  }

  clearFocus() {
    this.focusedWidget.set(null);
  }
}

