@Injectable({
  providedIn: 'root'
})
export class MarketSimulatorService implements OnDestroy {
  private stateService = inject(TokenStateService);
  private prefs = inject(UserPrefsService);

  private tokens: Token[] = [];

  // Heartbeat State
  readonly timerProgress = signal(0); // 0 to 100
  readonly isUpdating = signal(false);
  readonly currentDuration = signal(5000); // Default Sim duration

  private timerId: any;
  private startTime = 0;
  private duration = 5000;

  constructor() {
    this.addToken('SOL', 'solana', 'Solana');
    this.addToken('JUP', 'jupiter-exchange-solana', 'Jupiter');
    this.addToken('WIF', 'dogwifcoin', 'dogwifhat');
    this.addToken('USDC', 'usd-coin', 'USD Coin');

    // React to configuration changes
    effect(() => {
      const mode = this.prefs.dataSourceMode();
      const rate = this.prefs.refreshRate();
      this.configureHeartbeat(mode, rate);
    });
  }

  // --- PUBLIC API ---

  async searchTokens(query: string): Promise<TokenDefinition[]> {
    const q = query.toUpperCase().trim();
    if (!q) return [];
    const localMatches = SOLANA_TOKEN_DB.filter(t => 
      t.symbol.includes(q) || t.name.toUpperCase().includes(q)
    );

    // If Custom or Simulation, rely on local DB to avoid external calls that might not match context
    if (this.prefs.dataSourceMode() === 'SIMULATION' || this.prefs.dataSourceMode() === 'CUSTOM') {
      return localMatches;
    }

    try {
      const response = await fetch(`https://api.coingecko.com/api/v3/search?query=${query}`);
      if (!response.ok) throw new Error('Search failed');

      const data = await response.json();
      const remoteMatches: TokenDefinition[] = (data.coins || []).slice(0, 8).map((c: any) => ({
        symbol: c.symbol,
        name: c.name,
        cgId: c.id,
        price: undefined,
        isExternal: true
      }));

      const localSymbols = new Set(localMatches.map(t => t.symbol.toUpperCase()));
      const newRemote = remoteMatches.filter(r => !localSymbols.has(r.symbol.toUpperCase()));

      return [...localMatches, ...newRemote];
    } catch (err) {
      console.warn('Live search failed', err);
      return localMatches;
    }
  }

  addToken(symbol: string, cgId?: string, name?: string) {
    const s = symbol.toUpperCase().trim();
    if (!s || this.tokens.find(t => t.symbol === s)) return;

    const dbToken = SOLANA_TOKEN_DB.find(t => t.symbol === s);
    const finalCgId = cgId || dbToken?.cgId;
    const finalName = name || dbToken?.name || `${s} (Custom)`;

    let startPrice = dbToken?.price || 0;

    if (!dbToken && !cgId && this.prefs.dataSourceMode() === 'SIMULATION') {
      startPrice = Math.random() * 10 + 0.1;
    }

    const newToken = this.createToken(
      s,
      finalName,
      startPrice,
      startPrice > 0 ? startPrice * 0.95 : 0, 
      0, 
      finalCgId
    );

    this.fillTokenHistory(newToken);
    this.tokens = [...this.tokens, newToken];
    this.stateService.updateTokens([...this.tokens]);

    if (this.prefs.dataSourceMode() !== 'SIMULATION') {
      this.performUpdate(); // Immediate fetch for Live or Custom
    }
  }

  removeToken(symbol: string) {
    this.tokens = this.tokens.filter(t => t.symbol !== symbol);
    this.stateService.updateTokens([...this.tokens]);
  }

  // --- HEARTBEAT ENGINE ---

  private configureHeartbeat(mode: DataSourceMode, rate: RefreshRate) {
    if (this.timerId) clearInterval(this.timerId);

    // Calculate duration
    let ms = 5000;
    // Live AND Custom both respect the user's refresh rate choice
    if (mode === 'LIVE' || mode === 'CUSTOM') {
      switch (rate) {
        case 'AGGRESSIVE': ms = 30000; break; // 30s
        case 'STANDARD': ms = 60000; break;   // 60s
        case 'SAFE': ms = 120000; break;      // 2m
      }
    }

    this.duration = ms;
    this.currentDuration.set(this.duration);
    this.startTime = Date.now();

    // Initial update if switching modes
    this.performUpdate();

    // The Tick Loop (runs at 10fps for UI smoothness)
    this.timerId = setInterval(() => {
      const now = Date.now();
      const elapsed = now - this.startTime;

      if (elapsed >= this.duration) {
        // Cycle Complete
        this.performUpdate();
        this.startTime = Date.now();
        this.timerProgress.set(0);
      } else {
        // Update Progress
        const p = (elapsed / this.duration) * 100;
        this.timerProgress.set(p);
      }
    }, 100);
  }

  private async performUpdate() {
    this.isUpdating.set(true);

    const mode = this.prefs.dataSourceMode();

    if (mode === 'SIMULATION') {
      this.updateMarketSimulated();
    } else if (mode === 'LIVE') {
      await this.fetchLiveData();
    } else if (mode === 'CUSTOM') {
      await this.fetchCustomData();
    }

    // Keep "Updating" state true for at least 500ms so the user sees the flash
    setTimeout(() => {
      this.isUpdating.set(false);
    }, 500);
  }

  // --- DATA LOGIC ---

  private createToken(symbol: string, name: string, price: number, entry: number, apy: number, cgId?: string): Token & { cgId?: string } {
    return {
      symbol,
      name,
      price,
      entryPrice: entry,
      volume: 1000000 + Math.random() * 5000000,
      yield: apy,
      priceHistory: [],
      volumeHistory: [],
      liquidityDepth: 5000000 + Math.random() * 5000000,
      cgId: cgId
    } as any;
  }

  private fillTokenHistory(token: Token) {
    let currentPrice = token.price || 1; 
    let currentVol = token.volume;

    for (let i = 0; i < 60; i++) {
      const change = (Math.random() - 0.5) * 0.02;
      currentPrice = currentPrice * (1 - change);
      currentVol = currentVol * (0.8 + Math.random() * 0.4);
      token.priceHistory.unshift(currentPrice);
      token.volumeHistory.unshift(currentVol);
    }
  }

  private updateMarketSimulated() {
    const updatedTokens = this.tokens.map(token => {
      if (token.price === 0) token.price = Math.random() * 10;

      const volatility = (token.symbol === 'USDC' || token.symbol === 'USDT') ? 0.001 : 0.015;
      const change = (Math.random() - 0.5) * volatility * 2;
      const newPrice = token.price * (1 + change);

      const isBurst = Math.random() > 0.95;
      const newVolume = isBurst 
        ? token.volume * (3 + Math.random()) 
        : token.volume * (0.8 + Math.random() * 0.4);

      const newLiquidity = Math.random() > 0.9 ? 500000 : 5000000 + Math.random() * 5000000;

      const newPriceHistory = [...token.priceHistory, newPrice].slice(-60);
      const newVolumeHistory = [...token.volumeHistory, newVolume].slice(-60);

      return {
        ...token,
        price: newPrice,
        volume: newVolume,
        liquidityDepth: newLiquidity,
        priceHistory: newPriceHistory,
        volumeHistory: newVolumeHistory
      };
    });

    this.tokens = updatedTokens;
    this.stateService.updateTokens(updatedTokens);
  }

  private async fetchLiveData() {
    const tokensWithIds = this.tokens.filter(t => (t as any).cgId);
    if (tokensWithIds.length === 0) return;

    const ids = tokensWithIds.map(t => (t as any).cgId).join(',');

    try {
      const response = await fetch(
        `https://api.coingecko.com/api/v3/simple/price?ids=${ids}&vs_currencies=usd&include_24hr_vol=true`
      );

      if (!response.ok) throw new Error('API Error');

      const data = await response.json();

      const updatedTokens = this.tokens.map(token => {
        const cgId = (token as any).cgId;
        if (cgId && data[cgId]) {
          const apiData = data[cgId];
          const newPrice = apiData.usd;
          const newVol = apiData.usd_24h_vol;

          const newPriceHistory = [...token.priceHistory, newPrice].slice(-60);
          const newVolumeHistory = [...token.volumeHistory, newVol].slice(-60);

          return {
            ...token,
            price: newPrice,
            volume: newVol,
            priceHistory: newPriceHistory,
            volumeHistory: newVolumeHistory
          };
        }
        return token;
      });

      this.tokens = updatedTokens;
      this.stateService.updateTokens(updatedTokens);

    } catch (err) {
      console.warn('AXIOM: Live fetch failed.', err);
    }
  }

  private async fetchCustomData() {
    const url = this.prefs.customApiUrl();
    if (!url) return;

    try {
      const response = await fetch(url);
      if (!response.ok) throw new Error(`Custom API Error: ${response.statusText}`);
      const data = await response.json();

      // Support generic list of objects with 'symbol' and 'price'/'volume'
      // OR Object with keys as symbols

      const updatedTokens = this.tokens.map(token => {
        let newPrice = token.price;
        let newVol = token.volume;
        let found = false;

        // Strategy 1: Array of objects
        if (Array.isArray(data)) {
          // Find case-insensitive match
          const match = data.find((d: any) => d.symbol?.toUpperCase() === token.symbol.toUpperCase());
          if (match) {
            newPrice = Number(match.price) || token.price;
            newVol = Number(match.volume) || token.volume;
            found = true;
          }
        } 
        // Strategy 2: Object keyed by symbol { "SOL": { ... }, "JUP": ... }
        else if (typeof data === 'object' && data !== null) {
          const key = Object.keys(data).find(k => k.toUpperCase() === token.symbol.toUpperCase());
          if (key) {
             const entry = data[key];
             if (typeof entry === 'object' && entry !== null) {
               newPrice = Number(entry.price) || Number(entry.usd) || token.price;
               newVol = Number(entry.volume) || Number(entry.usd_24h_vol) || token.volume;
             } else if (typeof entry === 'number') {
               newPrice = entry;
             }
             found = true;
          }
        }

        if (found) {
           const newPriceHistory = [...token.priceHistory, newPrice].slice(-60);
           const newVolumeHistory = [...token.volumeHistory, newVol].slice(-60);
           return {
             ...token,
             price: newPrice,
             volume: newVol,
             priceHistory: newPriceHistory,
             volumeHistory: newVolumeHistory
           };
        }
        return token;
      });

      this.tokens = updatedTokens;
      this.stateService.updateTokens(updatedTokens);

    } catch (err) {
      console.warn('AXIOM: Custom fetch failed.', err);
    }
  }

  ngOnDestroy() {
    if (this.timerId) clearInterval(this.timerId);
  }
}

import { Component, inject, signal, computed } from '@angular/core';
import { CommonModule } from '@angular/common';
import { TokenStateService } from './services/token-state.service';
import { MarketSimulatorService, TokenDefinition } from './services/market-simulator.service';
import { UserPrefsService, WidgetId } from './services/user-prefs.service';
import { IntelPanelComponent } from './components/intel-panel.component';
import { MarketGridComponent } from './components/market-grid.component';
import { SignalFeedComponent } from './components/signal-feed.component';
import { TokenDetailComponent } from './components/token-detail.component';
import { SyncIndicatorComponent } from './components/sync-indicator.component';
import { LogoComponent } from './components/logo.component';

@Component({
  selector: 'app-root',
  standalone: true,
  imports: [
    CommonModule, 
    IntelPanelComponent,
    MarketGridComponent,
    SignalFeedComponent,
    TokenDetailComponent,
    SyncIndicatorComponent,
    LogoComponent
  ],
  templateUrl: './app.component.html',
})
export class AppComponent {
  private stateService = inject(TokenStateService);
  private simulator = inject(MarketSimulatorService);
  public prefs = inject(UserPrefsService);

  // Expose signals for template
  tokens = this.stateService.tokens;
  regime = this.stateService.marketRegime;
  activeSignals = this.stateService.filteredSignals; // Use filtered signals
  selectedTokenSymbol = this.stateService.selectedTokenSymbol;

  // Heartbeat Signals
  timerProgress = this.simulator.timerProgress;
  isUpdating = this.simulator.isUpdating;
  timerDuration = this.simulator.currentDuration;

  // Computed: Get full token object for the selected symbol
  selectedTokenObject = computed(() => {
    const sym = this.selectedTokenSymbol();
    if (!sym) return null;
    return this.tokens().find(t => t.symbol === sym) || null;
  });

  terminalId = Math.random().toString(36).substring(7).toUpperCase();

  // Settings Modal State
  showSettings = signal(false);

  // Watchlist Editor State
  showWatchlistEditor = signal(false);
  tokenSearchTerm = signal('');

  // Async Search State
  tokenSuggestions = signal<TokenDefinition[]>([]);
  isSearching = signal(false);
  private searchTimeout: any;

  toggleSettings() {
    this.showSettings.update(v => !v);
  }

  toggleWatchlistEditor() {
    this.showWatchlistEditor.update(v => !v);
    this.tokenSearchTerm.set('');
    this.tokenSuggestions.set([]);
  }

  updateCustomUrl(event: Event) {
    const val = (event.target as HTMLInputElement).value;
    this.prefs.setCustomApiUrl(val);
  }

  updateSearchTerm(event: Event) {
    const input = event.target as HTMLInputElement;
    const val = input.value;
    this.tokenSearchTerm.set(val);

    // Debounce search
    clearTimeout(this.searchTimeout);

    if (!val.trim()) {
      this.tokenSuggestions.set([]);
      this.isSearching.set(false);
      return;
    }

    this.isSearching.set(true);
    this.searchTimeout = setTimeout(async () => {
      const results = await this.simulator.searchTokens(val);

      // Filter out tokens already in the user's watchlist
      const currentSymbols = new Set(this.tokens().map(t => t.symbol.toUpperCase()));
      const filtered = results.filter(r => !currentSymbols.has(r.symbol.toUpperCase()));

      this.tokenSuggestions.set(filtered);
      this.isSearching.set(false);
    }, 500); 
  }

  handleAddToken(suggestion: TokenDefinition) {
    this.simulator.addToken(suggestion.symbol, suggestion.cgId, suggestion.name);
    this.tokenSearchTerm.set('');
    this.tokenSuggestions.set([]);
  }

  // Fallback for enter key on input
  handleManualAdd(term: string) {
    if(!term) return;
    // Check if there's a top suggestion match first
    const suggestions = this.tokenSuggestions();
    if (suggestions.length > 0) {
      this.handleAddToken(suggestions[0]);
    } else {
      this.simulator.addToken(term);
    }
    this.tokenSearchTerm.set('');
    this.tokenSuggestions.set([]);
  }

  handleRemoveToken(symbol: string) {
    this.simulator.removeToken(symbol);
  }

  handleTokenSelect(symbol: string) {
    this.stateService.toggleSelectedToken(symbol);
  }

  deselectToken() {
    // If we have a selected token, toggle it off by passing the same symbol
    const current = this.selectedTokenSymbol();
    if (current) {
      this.stateService.toggleSelectedToken(current);
    }
  }

  toggleFocus(id: WidgetId) {
    this.prefs.setFocus(id);
  }
}

