        this.state.tokens(),
        this.state.marketRegime(),
        this.state.activeSignals(),
        this.prefs.aiTone()
      );
      this.narrative.set(text);
    } catch (err) {
      this.narrative.set("ERR: LINK_FAILURE");
    } finally {
      this.loading.set(false);
    }
  }
}

