                   <div class="w-1 h-1 bg-slate-400 rounded-full animate-bounce"></div> COMPUTING STRATEGY...
                 </span>
               }

               @if (analysisMap().get(sig.id); as result) {
                 <div class="bg-slate-100 dark:bg-slate-800/80 p-2 rounded w-full border border-slate-200 dark:border-slate-700">
                    <div class="flex justify-between items-start mb-1">
                      <span class="text-[10px] text-blue-600 dark:text-blue-400 font-bold">GEMINI TACTICAL:</span>
                      <button (click)="clearAnalysis(sig.id)" class="text-[10px] text-slate-400 hover:text-slate-200">x</button>
                    </div>
                    <p class="text-[11px] text-slate-700 dark:text-slate-300 font-mono leading-tight">{{ result }}</p>
                 </div>
               }
            </div>

          </div>
        } @empty {
          <div class="flex flex-col items-center justify-center h-48 text-slate-400 dark:text-slate-600">
             <div class="text-2xl mb-2 opacity-20">///</div>
             <div class="text-xs font-mono">NO SIGNALS MATCHING FILTER</div>
          </div>
        }
      </div>

      <div class="p-1 bg-slate-100 dark:bg-slate-900 border-t border-slate-200 dark:border-slate-800 text-[10px] text-center text-slate-500 font-mono">
        {{ displayedSignals().length }} SIGNALS ACTIVE // PREDICTION ENGINE V3 (SQUEEZE)
      </div>
    </div>
  `
})
export class SignalFeedComponent {
  signals = input.required<Signal[]>();
  inspect = output<string>(); // Emit symbol

  private gemini = inject(GeminiService);
  private state = inject(TokenStateService);
  private prefs = inject(UserPrefsService);

  filter = signal<FilterType>('ALL');
  dismissedIds = signal<Set<string>>(new Set());

  // Local state for analysis results (ID -> String)
  analysisMap = signal<Map<string, string>>(new Map());
  analyzingState = signal<Set<string>>(new Set());

  displayedSignals = computed(() => {
    const list = this.signals().filter(s => !this.dismissedIds().has(s.id));
    const mode = this.filter();

    switch (mode) {
      case 'HIGH_CONFIDENCE':
        return list.filter(s => s.confidence >= 80);
      case 'OPPORTUNITY':
        return list.filter(s => s.severity === 'success' || s.severity === 'info');
      case 'RISK':
        return list.filter(s => s.severity === 'warning' || s.severity === 'danger');
      case 'PREDICTION':
        return list.filter(s => 
          s.type === SignalType.TREND_VECTOR || 
          s.type === SignalType.PATTERN_DETECTED ||
          s.type === SignalType.VOLATILITY_SQUEEZE
        );
      default:
        return list;
    }
  });

  setFilter(f: FilterType) {
    this.filter.set(f);
  }

  dismiss(id: string) {
    this.dismissedIds.update(set => {
      const n = new Set(set);
      n.add(id);
      return n;
    });
  }

  inspectSignal(sig: Signal) {
    this.inspect.emit(sig.tokenSymbol);
  }

  formatType(type: string): string {
    return type.replace(/_/g, ' ').replace('BUY', '').replace('SELL', '');
  }

  async analyze(sig: Signal) {
    // Check if we have the token data
    const token = this.state.tokens().find(t => t.symbol === sig.tokenSymbol);
    if (!token) return;

    // Set loading
    this.analyzingState.update(s => {
      const n = new Set(s);
      n.add(sig.id);
      return n;
    });

    try {
      const analysis = await this.gemini.analyzeSignalContext(sig, token);

      this.analysisMap.update(m => {
        const n = new Map(m);
        n.set(sig.id, analysis);
        return n;
      });
    } finally {
       this.analyzingState.update(s => {
        const n = new Set(s);
        n.delete(sig.id);
        return n;
      });
    }
  }

  clearAnalysis(id: string) {
    this.analysisMap.update(m => {
      const n = new Map(m);
      n.delete(id);
      return n;
    });
  }
}

import { Injectable, signal, computed } from '@angular/core';
import { Token, Signal, SignalType, MarketRegime } from './types';
import { MathUtils } from './math-utils';
import * as d3 from 'd3';

@Injectable({
  providedIn: 'root'
})
export class TokenStateService {
  // State
  readonly tokens = signal<Token[]>([]);
  readonly marketRegime = signal<MarketRegime>({ status: 'NEUTRAL', volatility: 0, correlation: 0 });
  readonly selectedTokenSymbol = signal<string | null>(null);

  // Computed Signals (The Algorithms)
  // Housekeeping: IDs are now deterministic (Type:Symbol) to ensure stability across ticks.
  readonly activeSignals = computed(() => {
    const currentTokens = this.tokens();
    let signals: Signal[] = [];

    currentTokens.forEach(token => {
      // 1. BURST HUNTER (Conviction)
      const smaVol20 = MathUtils.sma(token.volumeHistory, 20);
      if (smaVol20) {
        const currentVol = token.volume;
        const lastPrice = token.priceHistory[token.priceHistory.length - 2] || token.price;
        const priceChange = (token.price - lastPrice) / lastPrice;

        const ratio = currentVol / smaVol20;

        if (ratio > 3 && priceChange > 0.02) {
          const conf = Math.min(Math.round((ratio / 10) * 100), 99); 
          signals.push({
            id: `BURST:${token.symbol}`,
            timestamp: Date.now(), // Updates on each tick, showing "Freshness"
            type: SignalType.BURST_HUNTER,
            tokenSymbol: token.symbol,
            message: `Volume Burst: ${ratio.toFixed(1)}x normal.`,
            severity: 'success',
            confidence: conf
          });
        }
      }

      // 2. GAIN LOCK-100 (Risk Mgmt)
      const profitMargin = (token.price - token.entryPrice) / token.entryPrice;
      const sma10 = MathUtils.sma(token.priceHistory, 10);
      const sma50 = MathUtils.sma(token.priceHistory, 50);

      if (profitMargin > 1.0 && sma10 && sma50 && sma10 < sma50) {
         signals.push({
            id: `LOCK:${token.symbol}`,
            timestamp: Date.now(),
            type: SignalType.GAIN_LOCK,
            tokenSymbol: token.symbol,
            message: `Take Profit: +${(profitMargin * 100).toFixed(0)}% gain with Momentum Death Cross.`,
            severity: 'warning',
            confidence: 90 
          });
      }

      // 3. HYPE PULSE (Momentum)
      const rsi = MathUtils.rsi(token.priceHistory, 14);
      if (rsi && rsi > 70) {
        const conf = Math.min(Math.round(((rsi - 70) / 30) * 100) + 50, 95);
        signals.push({
            id: `HYPE_BUY:${token.symbol}`,
            timestamp: Date.now(),
            type: SignalType.HYPE_PULSE_BUY,
            tokenSymbol: token.symbol,
            message: `Overbought Hype: RSI at ${rsi.toFixed(0)}.`,
            severity: 'info',
            confidence: conf
          });
      }

      // 4. PREDICTION ENGINE: TREND VECTOR
      const historyShort = token.priceHistory.slice(-15);
      const regression = MathUtils.linearRegression(historyShort);

      if (regression) {
        const slopePercent = regression.m / token.price;
        if (Math.abs(slopePercent) > 0.005) {
           const direction = slopePercent > 0 ? 'UP' : 'DOWN';
           const projected = token.price + (regression.m * 5); 
           const conf = 75; 

           signals.push({
             id: `VECTOR:${token.symbol}`,
             timestamp: Date.now(),
             type: SignalType.TREND_VECTOR,
             tokenSymbol: token.symbol,
             message: `Trend Vector: Projecting ${projected.toFixed(2)} (${direction})`,
             severity: direction === 'UP' ? 'success' : 'danger',
             confidence: conf,
             meta: { projectedPrice: projected }
           });
        }
      }

      // 5. STABLE ANCHOR
      const volatility = MathUtils.stdDev(token.priceHistory.slice(-20)) / token.price; 
      if (volatility < 0.05 && token.yield > 5.0) {
         signals.push({
            id: `ANCHOR:${token.symbol}`,
            timestamp: Date.now(),
            type: SignalType.STABLE_ANCHOR,
            tokenSymbol: token.symbol,
            message: `Yield Safe Haven: ${token.yield.toFixed(2)}% APY.`,
            severity: 'success',
            confidence: 85
          });
      }

      // 6. VENUE SHIELD
      if (token.liquidityDepth < 1000000) { 
         signals.push({
            id: `VENUE:${token.symbol}`,
            timestamp: Date.now(),
            type: SignalType.VENUE_SHIELD,
            tokenSymbol: token.symbol,
            message: `High Slippage Risk: Low Liquidity.`,
            severity: 'danger',
            confidence: 100
          });
      }

      // 7. PATTERN SCANNER (Support Bounce)
      if (token.priceHistory.length > 20) {
         const recent = token.priceHistory.slice(-20);
         const minPrice = d3.min(recent) || 0;
         const current = token.price;
         const prev = token.priceHistory[token.priceHistory.length - 2];

         if (current > prev && (current - minPrice) / minPrice < 0.05 && current > minPrice) {
            signals.push({
              id: `PATTERN_BOUNCE:${token.symbol}`,
              timestamp: Date.now(),
              type: SignalType.PATTERN_DETECTED,
              tokenSymbol: token.symbol,
              message: `Support Bounce: Rebounding from 20-period low.`,
              severity: 'success',
              confidence: 60
            });
         }
      }

      // 8. VOLATILITY SQUEEZE (Prediction V3)
      if (token.priceHistory.length > 20) {
         const period = 20;
         const recent = token.priceHistory.slice(-period);
         const sma = MathUtils.sma(recent, period) || token.price;
         const stdDev = MathUtils.stdDev(recent);

         const upper = sma + (2 * stdDev);
         const lower = sma - (2 * stdDev);
         const bandwidth = (upper - lower) / sma;

         if (bandwidth < 0.01) {
            signals.push({
              id: `SQUEEZE:${token.symbol}`,
              timestamp: Date.now(),
              type: SignalType.VOLATILITY_SQUEEZE,
              tokenSymbol: token.symbol,
              message: `Volatility Squeeze: Breakout imminent (Bandwidth ${(bandwidth*100).toFixed(2)}%).`,
              severity: 'warning',
              confidence: 80
            });
         }
      }
    });

    return signals.sort((a, b) => b.timestamp - a.timestamp);
  });

  readonly filteredSignals = computed(() => {
    const signals = this.activeSignals();
    const selected = this.selectedTokenSymbol();

    if (!selected) {
      return signals;
    }

    return signals.filter(s => s.tokenSymbol === selected);
  });

  // Action: Update State
  updateTokens(newTokens: Token[]) {
    this.tokens.set(newTokens);
    this.updateRegime(newTokens);
  }

  toggleSelectedToken(symbol: string) {
    this.selectedTokenSymbol.update(current => current === symbol ? null : symbol);
  }

  updateSignalAnalysis(signalId: string, analysis: string) {
    // Logic handled in component state for transient analysis
  }

  private updateRegime(tokens: Token[]) {
    const avgVol = tokens.reduce((acc, t) => {
        const history = t.priceHistory.slice(-10);
        if (history.length === 0) return acc;
        const vol = MathUtils.stdDev(history) / MathUtils.average(history);
        return acc + vol;
    }, 0) / tokens.length;

    const upMoves = tokens.filter(t => t.price > t.priceHistory[t.priceHistory.length - 2]).length;
    const correlationFactor = Math.abs((upMoves / tokens.length) - 0.5) * 2; 

    let status: MarketRegime['status'] = 'NEUTRAL';
    if (avgVol > 0.015) status = 'VOLATILE'; 
    else if (correlationFactor > 0.6 && upMoves > tokens.length / 2) status = 'BULLISH';
    else if (correlationFactor > 0.6 && upMoves < tokens.length / 2) status = 'BEARISH';

    this.marketRegime.set({
      status,
      volatility: avgVol,
      correlation: correlationFactor
    });
  }
}

import { Injectable } from '@angular/core';
import { GoogleGenAI } from "@google/genai";
import { Token, MarketRegime, Signal } from './types';
