import { Component, inject, signal, computed, effect } from '@angular/core';
import { CommonModule, DOCUMENT } from '@angular/common';
import { TokenStateService } from './services/token-state.service';
import { MarketSimulatorService, TokenDefinition } from './services/market-simulator.service';
import { UserPrefsService, WidgetId } from './services/user-prefs.service';
import { IntelPanelComponent } from './components/intel-panel.component';
import { MarketGridComponent } from './components/market-grid.component';
import { SignalFeedComponent } from './components/signal-feed.component';
import { TokenDetailComponent } from './components/token-detail.component';
import { SyncIndicatorComponent } from './components/sync-indicator.component';
import { LogoComponent } from './components/logo.component';
import { AlgorithmDocsComponent } from './components/algorithm-docs.component';
import { AlgorithmIconComponent } from './components/algorithm-icon.component';

@Component({
  selector: 'app-root',
  standalone: true,
  imports: [
    CommonModule, 
    IntelPanelComponent,
    MarketGridComponent,
    SignalFeedComponent,
    TokenDetailComponent,
    SyncIndicatorComponent,
    LogoComponent,
    AlgorithmDocsComponent,
    AlgorithmIconComponent
  ],
  templateUrl: './app.component.html',
})
export class AppComponent {
  private stateService = inject(TokenStateService);
  private simulator = inject(MarketSimulatorService);
  public prefs = inject(UserPrefsService);
  private document = inject(DOCUMENT) as Document;

  // Expose signals for template
  tokens = this.stateService.tokens;
  regime = this.stateService.marketRegime;
  activeSignals = this.stateService.filteredSignals; // Use filtered signals
  selectedTokenSymbol = this.stateService.selectedTokenSymbol;

  // Heartbeat Signals
  timerProgress = this.simulator.timerProgress;
  isUpdating = this.simulator.isUpdating;
  timerDuration = this.simulator.currentDuration;

  // Computed: Get full token object for the selected symbol
  selectedTokenObject = computed(() => {
    const sym = this.selectedTokenSymbol();
    if (!sym) return null;
    return this.tokens().find(t => t.symbol === sym) || null;
  });

  terminalId = Math.random().toString(36).substring(7).toUpperCase();

  // Settings Modal State
  showSettings = signal(false);
  showDocs = signal(false);

  // Watchlist Editor State
  showWatchlistEditor = signal(false);
  tokenSearchTerm = signal('');

  // Async Search State
  tokenSuggestions = signal<TokenDefinition[]>([]);
  isSearching = signal(false);
  private searchTimeout: any;

  constructor() {
    // Theme Effect
    effect(() => {
      const theme = this.prefs.theme();
      const html = this.document.documentElement;
      if (theme === 'DARK') {
        html.classList.add('dark');
      } else {
        html.classList.remove('dark');
      }
    });
  }

  toggleSettings() {
    this.showSettings.update(v => !v);
  }

  toggleDocs() {
    this.showDocs.update(v => !v);
  }

  toggleWatchlistEditor() {
    this.showWatchlistEditor.update(v => !v);
    this.tokenSearchTerm.set('');
    this.tokenSuggestions.set([]);
  }

  updateCustomUrl(event: Event) {
    const val = (event.target as HTMLInputElement).value;
    this.prefs.setCustomApiUrl(val);
  }

  updateSearchTerm(event: Event) {
    const input = event.target as HTMLInputElement;
    const val = input.value;
    this.tokenSearchTerm.set(val);

    // Debounce search
    clearTimeout(this.searchTimeout);

    if (!val.trim()) {
      this.tokenSuggestions.set([]);
      this.isSearching.set(false);
      return;
    }

    this.isSearching.set(true);
    this.searchTimeout = setTimeout(async () => {
      const results = await this.simulator.searchTokens(val);

      // Filter out tokens already in the user's watchlist
      const currentSymbols = new Set(this.tokens().map(t => t.symbol.toUpperCase()));
      const filtered = results.filter(r => !currentSymbols.has(r.symbol.toUpperCase()));

      this.tokenSuggestions.set(filtered);
      this.isSearching.set(false);
    }, 500); 
  }

  handleAddToken(suggestion: TokenDefinition) {
    this.simulator.addToken(suggestion.symbol, suggestion.cgId, suggestion.name);
    this.tokenSearchTerm.set('');
    this.tokenSuggestions.set([]);
  }

  // Fallback for enter key on input
  handleManualAdd(term: string) {
    if(!term) return;
    // Check if there's a top suggestion match first
    const suggestions = this.tokenSuggestions();
    if (suggestions.length > 0) {
      this.handleAddToken(suggestions[0]);
    } else {
      this.simulator.addToken(term);
    }
    this.tokenSearchTerm.set('');
    this.tokenSuggestions.set([]);
  }

  handleRemoveToken(symbol: string) {
    this.simulator.removeToken(symbol);
  }

  handleTokenSelect(symbol: string) {
    this.stateService.toggleSelectedToken(symbol);
  }

  deselectToken() {
    // If we have a selected token, toggle it off by passing the same symbol
    const current = this.selectedTokenSymbol();
    if (current) {
      this.stateService.toggleSelectedToken(current);
    }
  }

  toggleFocus(id: WidgetId) {
    this.prefs.setFocus(id);
  }
}

export interface Token {
  symbol: string;
  name: string;
  price: number;
  entryPrice: number; // For Gain Lock-100
  volume: number;
  yield: number; // APY for Stable Anchor
  priceHistory: number[]; // For SMAs, RSI, Volatility
  volumeHistory: number[]; // For Burst Hunter
  liquidityDepth: number; // For Venue Shield
}

export enum SignalType {
  BURST_HUNTER = 'BURST_HUNTER', // Conviction
  GAIN_LOCK = 'GAIN_LOCK', // Risk Mgmt
  HYPE_PULSE_BUY = 'HYPE_PULSE_BUY', // Momentum
  HYPE_PULSE_SELL = 'HYPE_PULSE_SELL',
  STABLE_ANCHOR = 'STABLE_ANCHOR', // Capital Preservation
  VENUE_SHIELD = 'VENUE_SHIELD', // Execution
  TREND_VECTOR = 'TREND_VECTOR', // Linear Regression Prediction
  PATTERN_DETECTED = 'PATTERN_DETECTED', // Geometric/Candle Patterns
  VOLATILITY_SQUEEZE = 'VOLATILITY_SQUEEZE', // Bollinger Squeeze (Prediction)
  PRICE_ALERT = 'PRICE_ALERT' // User-defined price alert
}

export interface Signal {
  id: string;
  timestamp: number;
  type: SignalType;
  tokenSymbol: string;
  message: string;
  severity: 'info' | 'success' | 'warning' | 'danger';
  confidence: number; // 0 to 100
  aiAnalysis?: string; // Populated on demand
  isAnalyzing?: boolean; // UI state
  meta?: any; // For extra data like projected price
}

export interface MarketRegime {
  status: 'BULLISH' | 'BEARISH' | 'NEUTRAL' | 'VOLATILE';
  volatility: number;
  correlation: number;
}

export interface PriceAlert {
  targetPrice: number;
  condition: 'ABOVE' | 'BELOW';
}

import { Injectable, signal, computed } from '@angular/core';
import { Token, Signal, SignalType, MarketRegime, PriceAlert } from './types';
import { MathUtils } from './math-utils';
import * as d3 from 'd3';

@Injectable({
  providedIn: 'root'
})
export class TokenStateService {
  // State
  readonly tokens = signal<Token[]>([]);
  readonly marketRegime = signal<MarketRegime>({ status: 'NEUTRAL', volatility: 0, correlation: 0 });
  readonly selectedTokenSymbol = signal<string | null>(null);
  readonly priceAlerts = signal<Map<string, PriceAlert>>(new Map());

  // Computed Signals (The Algorithms)
  // Housekeeping: IDs are now deterministic (Type:Symbol) to ensure stability across ticks.
  readonly activeSignals = computed(() => {
    const currentTokens = this.tokens();
    const alerts = this.priceAlerts();
    let signals: Signal[] = [];

    currentTokens.forEach(token => {
      // 0. PRICE ALERTS (User Defined)
      const alert = alerts.get(token.symbol);
      if (alert) {
        const conditionMet = 
          (alert.condition === 'ABOVE' && token.price > alert.targetPrice) ||
          (alert.condition === 'BELOW' && token.price < alert.targetPrice);

        if (conditionMet) {
          signals.push({
            id: `PRICE_ALERT:${token.symbol}`,
            timestamp: Date.now(),
            type: SignalType.PRICE_ALERT,
            tokenSymbol: token.symbol,
            message: `Price crossed ${alert.condition.toLowerCase()} alert at $${alert.targetPrice.toFixed(4)}.`,
            severity: 'warning',
            confidence: 100 
          });
        }
      }

      // 1. BURST HUNTER (Conviction)
      const smaVol20 = MathUtils.sma(token.volumeHistory, 20);
      if (smaVol20) {
        const currentVol = token.volume;
        const lastPrice = token.priceHistory[token.priceHistory.length - 2] || token.price;
        const priceChange = (token.price - lastPrice) / lastPrice;

        const ratio = currentVol / smaVol20;

        if (ratio > 3 && priceChange > 0.02) {
          const conf = Math.min(Math.round((ratio / 10) * 100), 99); 
          signals.push({
            id: `BURST:${token.symbol}`,
            timestamp: Date.now(), // Updates on each tick, showing "Freshness"
            type: SignalType.BURST_HUNTER,
            tokenSymbol: token.symbol,
            message: `Volume Burst: ${ratio.toFixed(1)}x normal.`,
            severity: 'success',
            confidence: conf
          });
        }
      }

      // 2. GAIN LOCK-100 (Risk Mgmt)
      const profitMargin = (token.price - token.entryPrice) / token.entryPrice;
      const sma10 = MathUtils.sma(token.priceHistory, 10);
      const sma50 = MathUtils.sma(token.priceHistory, 50);

      if (profitMargin > 1.0 && sma10 && sma50 && sma10 < sma50) {
         signals.push({
            id: `LOCK:${token.symbol}`,
            timestamp: Date.now(),
            type: SignalType.GAIN_LOCK,
            tokenSymbol: token.symbol,
            message: `Take Profit: +${(profitMargin * 100).toFixed(0)}% gain with Momentum Death Cross.`,
            severity: 'warning',
            confidence: 90 
          });
      }

      // 3. HYPE PULSE (Momentum)
      const rsi = MathUtils.rsi(token.priceHistory, 14);
      if (rsi && rsi > 70) {
        const conf = Math.min(Math.round(((rsi - 70) / 30) * 100) + 50, 95);
        signals.push({
            id: `HYPE_BUY:${token.symbol}`,
            timestamp: Date.now(),
            type: SignalType.HYPE_PULSE_BUY,
            tokenSymbol: token.symbol,
            message: `Overbought Hype: RSI at ${rsi.toFixed(0)}.`,
            severity: 'info',
            confidence: conf
          });
      }

      // 4. PREDICTION ENGINE: TREND VECTOR
      const historyShort = token.priceHistory.slice(-15);
      const regression = MathUtils.linearRegression(historyShort);

      if (regression) {
        const slopePercent = regression.m / token.price;
        if (Math.abs(slopePercent) > 0.005) {
           const direction = slopePercent > 0 ? 'UP' : 'DOWN';
           const projected = token.price + (regression.m * 5); 
           const conf = 75; 

           signals.push({
             id: `VECTOR:${token.symbol}`,
             timestamp: Date.now(),
             type: SignalType.TREND_VECTOR,
             tokenSymbol: token.symbol,
             message: `Trend Vector: Projecting ${projected.toFixed(2)} (${direction})`,
             severity: direction === 'UP' ? 'success' : 'danger',
             confidence: conf,
             meta: { projectedPrice: projected }
           });
        }
      }

      // 5. STABLE ANCHOR
      const volatility = MathUtils.stdDev(token.priceHistory.slice(-20)) / token.price; 
      if (volatility < 0.05 && token.yield > 5.0) {
         signals.push({
            id: `ANCHOR:${token.symbol}`,
            timestamp: Date.now(),
            type: SignalType.STABLE_ANCHOR,
            tokenSymbol: token.symbol,
            message: `Yield Safe Haven: ${token.yield.toFixed(2)}% APY.`,
            severity: 'success',
            confidence: 85
          });
      }

      // 6. VENUE SHIELD
      if (token.liquidityDepth < 1000000) { 
         signals.push({
            id: `VENUE:${token.symbol}`,
            timestamp: Date.now(),
            type: SignalType.VENUE_SHIELD,
            tokenSymbol: token.symbol,
            message: `High Slippage Risk: Low Liquidity.`,
            severity: 'danger',
            confidence: 100
          });
      }

      // 7. PATTERN SCANNER (Support Bounce)
      if (token.priceHistory.length > 20) {
         const recent = token.priceHistory.slice(-20);
         const minPrice = d3.min(recent) || 0;
         const current = token.price;
         const prev = token.priceHistory[token.priceHistory.length - 2];

         if (current > prev && (current - minPrice) / minPrice < 0.05 && current > minPrice) {
            signals.push({
              id: `PATTERN_BOUNCE:${token.symbol}`,
              timestamp: Date.now(),
              type: SignalType.PATTERN_DETECTED,
              tokenSymbol: token.symbol,
              message: `Support Bounce: Rebounding from 20-period low.`,
              severity: 'success',
              confidence: 60
            });
         }
      }

      // 8. VOLATILITY SQUEEZE (Prediction V3)
      if (token.priceHistory.length > 20) {
         const period = 20;
         const recent = token.priceHistory.slice(-period);
         const sma = MathUtils.sma(recent, period) || token.price;
         const stdDev = MathUtils.stdDev(recent);

         const upper = sma + (2 * stdDev);
         const lower = sma - (2 * stdDev);
         const bandwidth = (upper - lower) / sma;

         if (bandwidth < 0.01) {
            signals.push({
              id: `SQUEEZE:${token.symbol}`,
              timestamp: Date.now(),
              type: SignalType.VOLATILITY_SQUEEZE,
              tokenSymbol: token.symbol,
              message: `Volatility Squeeze: Breakout imminent (Bandwidth ${(bandwidth*100).toFixed(2)}%).`,
              severity: 'warning',
              confidence: 80
            });
         }
      }
    });

    return signals.sort((a, b) => b.timestamp - a.timestamp);
  });

  readonly filteredSignals = computed(() => {
    const signals = this.activeSignals();
    const selected = this.selectedTokenSymbol();

    if (!selected) {
      return signals;
    }

    return signals.filter(s => s.tokenSymbol === selected);
  });

  // Action: Update State
  updateTokens(newTokens: Token[]) {
    this.tokens.set(newTokens);
    this.updateRegime(newTokens);
  }

  toggleSelectedToken(symbol: string) {
    this.selectedTokenSymbol.update(current => current === symbol ? null : symbol);
  }

  // --- Price Alert Actions ---
  setPriceAlert(symbol: string, targetPrice: number, condition: 'ABOVE' | 'BELOW') {
    if (!targetPrice || targetPrice <= 0) {
      this.removePriceAlert(symbol);
      return;
    }
    this.priceAlerts.update(alerts => {
      const newAlerts = new Map(alerts);
      newAlerts.set(symbol, { targetPrice, condition });
      return newAlerts;
    });
  }

  removePriceAlert(symbol: string) {
    this.priceAlerts.update(alerts => {
      const newAlerts = new Map(alerts);
      newAlerts.delete(symbol);
      return newAlerts;
    });
  }

  private updateRegime(tokens: Token[]) {
    if (tokens.length === 0) return;
    const avgVol = tokens.reduce((acc, t) => {
        const history = t.priceHistory.slice(-10);
        if (history.length === 0) return acc;
        const vol = MathUtils.stdDev(history) / MathUtils.average(history);
        return acc + vol;
    }, 0) / tokens.length;

    const upMoves = tokens.filter(t => t.priceHistory.length > 1 && t.price > t.priceHistory[t.priceHistory.length - 2]).length;
    const correlationFactor = Math.abs((upMoves / tokens.length) - 0.5) * 2; 

    let status: MarketRegime['status'] = 'NEUTRAL';
    if (avgVol > 0.015) status = 'VOLATILE'; 
    else if (correlationFactor > 0.6 && upMoves > tokens.length / 2) status = 'BULLISH';
    else if (correlationFactor > 0.6 && upMoves < tokens.length / 2) status = 'BEARISH';

    this.marketRegime.set({
      status,
      volatility: avgVol,
      correlation: correlationFactor
    });
  }
}

