    let targetPrice: number | null = null;
    let condition = this.alertCondition(); // Use the state of the toggle by default
    const currentPrice = this.token().price;

    // Check for percentage input
    if (value.endsWith('%')) {
      const percentage = parseFloat(value.slice(0, -1)) / 100;
      if (!isNaN(percentage) && currentPrice > 0) {
        targetPrice = currentPrice * (1 + percentage);
        // If percentage is used, derive the condition from its sign
        condition = percentage >= 0 ? 'ABOVE' : 'BELOW';
      }
    } else {
      // Assume absolute price
      const parsedPrice = parseFloat(value);
      if (!isNaN(parsedPrice)) {
        targetPrice = parsedPrice;
        // For absolute price, the user's selected toggle is respected.
      }
    }

    if (targetPrice !== null && targetPrice > 0) {
      this.stateService.setPriceAlert(this.token().symbol, targetPrice, condition);
    }
  }

  setQuickAlert(price: number, condition: 'ABOVE' | 'BELOW') {
    this.stateService.setPriceAlert(this.token().symbol, price, condition);
  }

  clearAlert() {
    this.stateService.removePriceAlert(this.token().symbol);
  }

  // D3 Chart Generation
  chartData = computed(() => {
    const history = this.token().priceHistory;
    if (!history || history.length < 2) return null;

    const data = history;
    const min = d3.min(data) || 0;
    const max = d3.max(data) || 0;
    const padding = (max - min) * 0.1;

    const xScale = d3.scaleLinear()
      .domain([0, data.length - 1])
      .range([0, 100]);

    const yScale = d3.scaleLinear()
      .domain([min - padding, max + padding])
      .range([50, 0]); // SVG ViewBox height is 50

    const lineGenerator = d3.line<number>()
      .x((d, i) => xScale(i))
      .y(d => yScale(d))
      .curve(d3.curveMonotoneX); // Smooth curve

    const areaGenerator = d3.area<number>()
      .x((d, i) => xScale(i))
      .y0(50) // Bottom of chart
      .y1(d => yScale(d))
      .curve(d3.curveMonotoneX);

    return {
      linePath: lineGenerator(data) || '',
      areaPath: areaGenerator(data) || '',
      min,
      max
    };
  });

  metrics = computed(() => {
    const t = this.token();

    // RSI
    const rsiVal = MathUtils.rsi(t.priceHistory, 14) || 50;

    // Volatility
    const vol = MathUtils.stdDev(t.priceHistory.slice(-20)) / t.price;

    // Trend
    const sma20 = MathUtils.sma(t.priceHistory, 20);
    const trend = sma20 && t.price > sma20 ? 'BULLISH' : 'BEARISH';

    // Volume Ratio
    const volSma = MathUtils.sma(t.volumeHistory, 20) || 1;
    const volRatio = t.volume / volSma;

    return {
      rsi: rsiVal,
      volatility: vol,
      trend,
      volRatio
    };
  });
}

