export class SignalFeedComponent {
  signals = input.required<Signal[]>();
  inspect = output<string>(); // Emit symbol

  private gemini = inject(GeminiService);
  private state = inject(TokenStateService);
  private prefs = inject(UserPrefsService);

  filter = signal<FilterType>('ALL');

  // Local state for analysis results (ID -> String)
  analysisMap = signal<Map<string, string>>(new Map());
  analyzingState = signal<Set<string>>(new Set());

  displayedSignals = computed(() => {
    const list = this.signals();
    const mode = this.filter();

    switch (mode) {
      case 'HIGH_CONFIDENCE':
        return list.filter(s => s.confidence >= 80);
      case 'OPPORTUNITY':
        return list.filter(s => s.severity === 'success' || s.severity === 'info');
      case 'RISK':
        return list.filter(s => s.severity === 'warning' || s.severity === 'danger');
      case 'PREDICTION':
        return list.filter(s => 
          s.type === SignalType.TREND_VECTOR || 
          s.type === SignalType.SUPPORT_BOUNCE ||
          s.type === SignalType.VOLATILITY_SQUEEZE ||
          s.type === SignalType.JERRY_REVERSION
        );
      default:
        return list;
    }
  });

  setFilter(f: FilterType) {
    this.filter.set(f);
  }

  inspectSignal(sig: Signal) {
    this.inspect.emit(sig.tokenSymbol);
  }

  formatType(type: string): string {
    return type.replace(/_/g, ' ').replace('BUY', '').replace('SELL', '');
  }

  getIconForSignal(type: SignalType): AlgoIconType {
    if (type === SignalType.HYPE_PULSE_BUY || type === SignalType.HYPE_PULSE_SELL) {
      return 'HYPE_PULSE';
    }
    if (type === SignalType.PRICE_ALERT) {
      return 'GAIN_LOCK';
    }
    if (type === SignalType.SUPPORT_BOUNCE) {
      return 'PATTERN_SCANNER';
    }
    return type as AlgoIconType;
  }

  async analyze(sig: Signal) {
    // Check if we have the token data
    const token = this.state.tokens().find(t => t.symbol === sig.tokenSymbol);
    if (!token) return;

    // Set loading
    this.analyzingState.update(s => {
      const n = new Set(s);
      n.add(sig.id);
      return n;
    });

    try {
      const analysis = await this.gemini.analyzeSignalContext(sig, token);

      this.analysisMap.update(m => {
        const n = new Map(m);
        n.set(sig.id, analysis);
        return n;
      });
    } finally {
       this.analyzingState.update(s => {
        const n = new Set(s);
        n.delete(sig.id);
        return n;
      });
    }
  }

  clearAnalysis(id: string) {
    this.analysisMap.update(m => {
      const n = new Map(m);
      n.delete(id);
      return n;
    });
  }
}

import { Injectable, inject, signal, effect } from '@angular/core';
import { TokenStateService } from './token-state.service';
import { Signal, SignalType, PerformanceData } from './types';

interface PendingSignal {
    signal: Signal;
    entryPrice: number;
    startTick: number;
}

@Injectable({
  providedIn: 'root'
})
export class PerformanceTrackerService {
    private tokenState = inject(TokenStateService);

    readonly stats = signal<Map<SignalType, PerformanceData>>(new Map());

    private pendingSignals = new Map<string, PendingSignal>();
    private processedSignalIds = new Set<string>();
    private tickCounter = 0;
    private readonly RESOLUTION_TICKS = 5; // Resolve after 5 ticks

    constructor() {
        effect(() => {
            this.tokenState.tokens(); // Depend on tokens to trigger effect on each data update
            this.tickCounter++;

            // It's important to process new signals *before* resolving old ones
            // to correctly capture the entry price on the tick the signal appeared.
            this.processNewSignals(this.tokenState.activeSignals());
            this.resolvePendingSignals();
        });
    }

    private processNewSignals(signals: Signal[]): void {
        const trackableSignals = signals.filter(s => this.isTrackable(s));

        for (const signal of trackableSignals) {
            if (!this.processedSignalIds.has(signal.id)) {
                const token = this.tokenState.tokens().find(t => t.symbol === signal.tokenSymbol);
                if (token) {
                    this.pendingSignals.set(signal.id, {
                        signal,
                        entryPrice: token.price,
                        startTick: this.tickCounter
                    });
                    this.processedSignalIds.add(signal.id);
                }
            }
        }
    }

    private resolvePendingSignals(): void {
        if (this.pendingSignals.size === 0) return;

        for (const [id, pending] of this.pendingSignals.entries()) {
            if (this.tickCounter >= pending.startTick + this.RESOLUTION_TICKS) {
                const token = this.tokenState.tokens().find(t => t.symbol === pending.signal.tokenSymbol);
                if (token) {
                    this.calculateOutcome(pending, token.price);
                    this.pendingSignals.delete(id);
                }
            }
        }
    }

    private calculateOutcome(pending: PendingSignal, exitPrice: number): void {
        const { signal, entryPrice } = pending;
        if (entryPrice === 0) return; // Avoid division by zero

        const returnPercent = ((exitPrice - entryPrice) / entryPrice) * 100;

        // For this simulation, all trackable signals are 'success' oriented, meaning they predict a price increase.
        const isWin = returnPercent > 0.05; // Consider it a win only if it's a meaningful gain (>0.05%)

        this.stats.update(currentStats => {
            const newStats = new Map(currentStats);
            // FIX: Explicitly type `existing` to work around a potential type inference issue where it was being inferred as 'unknown'.
            const existing: PerformanceData | undefined = newStats.get(signal.type);

            const wins = (existing?.wins ?? 0) + (isWin ? 1 : 0);
            const losses = (existing?.losses ?? 0) + (isWin ? 0 : 1);
            const totalSignals = (existing?.totalSignals ?? 0) + 1;
            const totalPnlPercent = (existing?.totalPnlPercent ?? 0) + returnPercent;

            const updatedData: PerformanceData = {
                totalSignals,
                wins,
                losses,
                winRate: (wins / totalSignals) * 100,
                totalPnlPercent,
                averageReturn: totalPnlPercent / totalSignals,
            };

            newStats.set(signal.type, updatedData);
            return newStats;
        });
    }

    resetStats(): void {
        this.stats.set(new Map());
        this.pendingSignals.clear();
        this.processedSignalIds.clear();
        console.log('AXIOM: Performance audit data has been reset.');
    }

    private isTrackable(signal: Signal): boolean {
        const trackableTypes = [
            SignalType.BURST_HUNTER,
            SignalType.SUPPORT_BOUNCE,
            SignalType.JERRY_REVERSION,
            SignalType.VOLATILITY_SQUEEZE,
            SignalType.TREND_VECTOR,
        ];
        // For TREND_VECTOR, only track 'UP' predictions.
        if (signal.type === SignalType.TREND_VECTOR && signal.severity === 'danger') {
            return false;
        }
        return trackableTypes.includes(signal.type);
    }

    private getInitialData(): PerformanceData {
        return { totalSignals: 0, wins: 0, losses: 0, winRate: 0, totalPnlPercent: 0, averageReturn: 0 };
    }
}

import { Injectable, signal, computed } from '@angular/core';
import { Token, Signal, SignalType, MarketRegime, PriceAlert } from './types';
import { MathUtils } from './math-utils';
import * as d3 from 'd3';

@Injectable({
  providedIn: 'root'
})
export class TokenStateService {
  // State
  readonly tokens = signal<Token[]>([]);
  readonly marketRegime = signal<MarketRegime>({ status: 'NEUTRAL', volatility: 0, correlation: 0 });
  readonly selectedTokenSymbol = signal<string | null>(null);
  readonly priceAlerts = signal<Map<string, PriceAlert>>(new Map());

  // Computed Signals (The Algorithms)
  // Housekeeping: IDs are now deterministic (Type:Symbol) to ensure stability across ticks.
  readonly activeSignals = computed(() => {
    const currentTokens = this.tokens();
    const alerts = this.priceAlerts();
    const marketRegime = this.marketRegime();
    const marketSummary = this.marketSummary();
    let signals: Signal[] = [];

    currentTokens.forEach(token => {
      // 0. PRICE ALERTS (User Defined)
      const alert = alerts.get(token.symbol);
      if (alert) {
        const conditionMet = 
          (alert.condition === 'ABOVE' && token.price > alert.targetPrice) ||
          (alert.condition === 'BELOW' && token.price < alert.targetPrice);

        if (conditionMet) {
          signals.push({
            id: `PRICE_ALERT:${token.symbol}`,
            timestamp: Date.now(),
            type: SignalType.PRICE_ALERT,
            tokenSymbol: token.symbol,
            message: `Price crossed ${alert.condition.toLowerCase()} alert at $${alert.targetPrice.toFixed(4)}.`,
            severity: 'warning',
            confidence: 100 
          });
        }
      }

      // --- PRE-CALCULATE COMMON INDICATORS ---
      const rsi = MathUtils.rsi(token.priceHistory, 14);
      const sma10 = MathUtils.sma(token.priceHistory, 10);
      const sma20 = MathUtils.sma(token.priceHistory, 20);
      const sma50 = MathUtils.sma(token.priceHistory, 50);

      // 1. BURST HUNTER (Conviction)
      const smaVol20 = MathUtils.sma(token.volumeHistory, 20);
      if (smaVol20 && token.priceHistory.length > 3 && sma20) {
        const lastPrice = token.priceHistory[token.priceHistory.length - 2];
        const prevLastPrice = token.priceHistory[token.priceHistory.length - 3];
        const priceChange = (token.price - lastPrice) / lastPrice;
        const prevPriceChange = (lastPrice - prevLastPrice) / prevLastPrice;
        const isAccelerating = priceChange > prevPriceChange;
        const ratio = token.volume / smaVol20;
        const inUptrend = token.price > sma20;

        if (ratio > 3.5 && priceChange > 0.02 && isAccelerating && inUptrend) {
          let conf = Math.min(Math.round((ratio / 10) * 100), 85) + 5;
          // NEW: Macro Confirmation
          const marketBreadth = marketSummary.advancing / (marketSummary.advancing + marketSummary.declining || 1);
          if (marketBreadth > 0.6) conf = Math.min(conf + 10, 99);

          signals.push({
            id: `BURST:${token.symbol}`,
            timestamp: Date.now(),
            type: SignalType.BURST_HUNTER,
            tokenSymbol: token.symbol,
            message: `Macro-Confirmed Volume Burst: ${ratio.toFixed(1)}x normal.`,
            severity: 'success',
            confidence: conf
          });
        }
      }

      // 2. GAIN LOCK-100 (Risk Mgmt)
      const profitMargin = (token.price - token.entryPrice) / token.entryPrice;
      if (profitMargin > 1.0 && sma10 && sma50 && sma10 < sma50) {
         signals.push({
            id: `LOCK:${token.symbol}`,
            timestamp: Date.now(),
            type: SignalType.GAIN_LOCK,
            tokenSymbol: token.symbol,
            message: `Take Profit: +${(profitMargin * 100).toFixed(0)}% gain with Momentum Death Cross.`,
            severity: 'warning',
            confidence: 90 
          });
      }

      // 3. HYPE PULSE (Momentum) - NOW WITH DYNAMIC THRESHOLDS
      if (rsi) {
        let overboughtThreshold = 70;
        let oversoldThreshold = 30;
        if (marketRegime.status === 'BULLISH') {
          overboughtThreshold = 80;
          oversoldThreshold = 40;
        } else if (marketRegime.status === 'BEARISH') {
          overboughtThreshold = 60;
          oversoldThreshold = 20;
        }

        if (rsi > overboughtThreshold) {
          const conf = Math.min(Math.round(((rsi - overboughtThreshold) / (100 - overboughtThreshold)) * 100) + 50, 95);
          signals.push({
              id: `HYPE_BUY:${token.symbol}`,
              timestamp: Date.now(),
              type: SignalType.HYPE_PULSE_BUY,
              tokenSymbol: token.symbol,
              message: `Overbought (RSI > ${overboughtThreshold}): ${rsi.toFixed(0)}.`,
              severity: 'info',
              confidence: conf
          });
        }
      }

      // 4. PREDICTION ENGINE: TREND VECTOR - NOW WITH DYNAMIC CONFIDENCE
      const historyShort = token.priceHistory.slice(-15);
      const regression = MathUtils.linearRegression(historyShort);

      // Dynamically adjust required trend strength based on market volatility.
      const currentVolatility = marketRegime.volatility;
      const rSquaredThreshold = currentVolatility > 0.015 ? 0.75 : 0.60;

      // Do not predict in highly volatile markets.
      if (regression && sma50 && regression.r2 > rSquaredThreshold && currentVolatility < 0.025) {
        const slopePercent = regression.m / token.price;
        if (Math.abs(slopePercent) > 0.005) {
           const direction = slopePercent > 0 ? 'UP' : 'DOWN';
           const isConfirmed = (direction === 'UP' && token.price > sma50) || 
                               (direction === 'DOWN' && token.price < sma50);

           if (isConfirmed) {
              const projected = token.price + (regression.m * 5); 
              // Confidence now scales based on how much r2 exceeds the dynamic threshold.
              const conf = 85 + Math.round(((regression.r2 - rSquaredThreshold) / (1.0 - rSquaredThreshold)) * 14);

              signals.push({
                id: `VECTOR:${token.symbol}`,
                timestamp: Date.now(),
                type: SignalType.TREND_VECTOR,
                tokenSymbol: token.symbol,
                message: `Strong Trend Vector (R²=${regression.r2.toFixed(2)}): Projecting ${projected.toFixed(2)}`,
                severity: direction === 'UP' ? 'success' : 'danger',
                confidence: Math.min(conf, 99),
                meta: { projectedPrice: projected }
              });
           }
        }
      }

      // 5. STABLE ANCHOR
      const volatility = MathUtils.stdDev(token.priceHistory.slice(-20)) / token.price; 
      if (volatility < 0.05 && token.yield > 5.0) {
         signals.push({
            id: `ANCHOR:${token.symbol}`,
            timestamp: Date.now(),
            type: SignalType.STABLE_ANCHOR,
            tokenSymbol: token.symbol,
            message: `Yield Safe Haven: ${token.yield.toFixed(2)}% APY.`,
            severity: 'success',
            confidence: 85
          });
      }

      // 6. VENUE SHIELD
      if (token.liquidityDepth < 1000000) { 
         signals.push({
            id: `VENUE:${token.symbol}`,
            timestamp: Date.now(),
            type: SignalType.VENUE_SHIELD,
            tokenSymbol: token.symbol,
            message: `High Slippage Risk: Low Liquidity.`,
            severity: 'danger',
            confidence: 100
          });
      }

      // 7. SUPPORT BOUNCE
      if (token.priceHistory.length > 20 && token.volumeHistory.length > 2 && rsi && rsi < 65) {
         const recent = token.priceHistory.slice(-20);
         const minPrice = d3.min(recent) || 0;
         const current = token.price;
         const prev = token.priceHistory[token.priceHistory.length - 2];
         const volumeConf = token.volume > token.volumeHistory[token.volumeHistory.length - 2];

         if (current > prev && (current - minPrice) / minPrice < 0.05 && current > minPrice && volumeConf) {
            signals.push({
              id: `SUPPORT_BOUNCE:${token.symbol}`,
              timestamp: Date.now(),
              type: SignalType.SUPPORT_BOUNCE,
              tokenSymbol: token.symbol,
              message: `Volume-Confirmed Bounce off 20-period low.`,
              severity: 'success',
              confidence: 75
            });
         }
      }

      // 8. VOLATILITY SQUEEZE (Prediction V3)
      if (token.priceHistory.length > 20 && rsi && rsi > 40 && rsi < 60) {
         const period = 20;
         const recent = token.priceHistory.slice(-period);
         const sma = sma20 || token.price;
         const stdDev = MathUtils.stdDev(recent);

         const upper = sma + (2 * stdDev);
         const lower = sma - (2 * stdDev);
         const bandwidth = (upper - lower) / sma;

         if (bandwidth < 0.025) {
            const conf = 80 + Math.round(((0.025 - bandwidth) / 0.025) * 19);
            signals.push({
              id: `SQUEEZE:${token.symbol}`,
              timestamp: Date.now(),
              type: SignalType.VOLATILITY_SQUEEZE,
              tokenSymbol: token.symbol,
              message: `High-Compression Squeeze: (Bandwidth ${(bandwidth*100).toFixed(2)}%).`,
              severity: 'warning',
              confidence: Math.min(conf, 99)
            });
         }
      }

      // 9. JERRY ALGORITHM (Systematic Mean Reversion) - NOW REGIME-GATED
      // NEW: Only run in non-trending markets
      if ((marketRegime.status === 'NEUTRAL' || marketRegime.status === 'VOLATILE') && token.priceHistory.length > 20) {
        const stdDev20 = MathUtils.stdDev(token.priceHistory.slice(-20));
        const prevPrice = token.priceHistory[token.priceHistory.length - 2];
        const prevPrevPrice = token.priceHistory[token.priceHistory.length - 3];

        if (sma20 && stdDev20 && prevPrice && prevPrevPrice) {
          const currentVolatility = stdDev20 / token.price;
          const priceDeviation = (sma20 - token.price) / sma20;

          const isBelowMean = priceDeviation > 0.05;
          const isLowVolatility = currentVolatility < 0.10;
          const isReverting = token.price > prevPrice && prevPrice > prevPrevPrice;

          if (isBelowMean && isLowVolatility && isReverting) {
            let conf = 75;
            if (priceDeviation > 0.1) conf += 10;
            if (currentVolatility < 0.05) conf += 10;

            signals.push({
              id: `JERRY:${token.symbol}`,
              timestamp: Date.now(),
              type: SignalType.JERRY_REVERSION,
              tokenSymbol: token.symbol,
              message: `Confirmed Reversion: ${(priceDeviation * 100).toFixed(0)}% below mean.`,
              severity: 'success',
              confidence: Math.min(conf, 99)
            });
          }
        }
      }
    });

    return signals.sort((a, b) => b.timestamp - a.timestamp);
  });

  readonly filteredSignals = computed(() => {
    const signals = this.activeSignals();
    const selected = this.selectedTokenSymbol();

    if (!selected) {
      return signals;
    }

    return signals.filter(s => s.tokenSymbol === selected);
  });

  readonly marketSummary = computed(() => {
    const summary = { advancing: 0, declining: 0, unchanged: 0 };
    this.tokens().forEach(token => {
        if (token.priceHistory.length < 2) {
            summary.unchanged++;
            return;
        }
        const currentPrice = token.price;
        const prevPrice = token.priceHistory[token.priceHistory.length - 2];

        if (currentPrice > prevPrice) {
            summary.advancing++;
        } else if (currentPrice < prevPrice) {
            summary.declining++;
        } else {
            summary.unchanged++;
        }
    });
    return summary;
  });

  // Action: Update State
  updateTokens(newTokens: Token[]) {
    this.tokens.set(newTokens);
    this.updateRegime(newTokens);
  }

  toggleSelectedToken(symbol: string) {
    this.selectedTokenSymbol.update(current => current === symbol ? null : symbol);
  }

  // --- Price Alert Actions ---
  setPriceAlert(symbol: string, targetPrice: number, condition: 'ABOVE' | 'BELOW') {
    if (!targetPrice || targetPrice <= 0) {
      this.removePriceAlert(symbol);
      return;
    }
    this.priceAlerts.update(alerts => {
      const newAlerts = new Map(alerts);
      newAlerts.set(symbol, { targetPrice, condition });
      return newAlerts;
    });
  }

  removePriceAlert(symbol: string) {
    this.priceAlerts.update(alerts => {
      const newAlerts = new Map(alerts);
      newAlerts.delete(symbol);
      return newAlerts;
    });
  }

  private updateRegime(tokens: Token[]) {
    if (tokens.length === 0) return;
    const avgVol = tokens.reduce((acc, t) => {
        const history = t.priceHistory.slice(-10);
        if (history.length === 0) return acc;
        const vol = MathUtils.stdDev(history) / MathUtils.average(history);
        return acc + vol;
    }, 0) / tokens.length;

    const upMoves = tokens.filter(t => t.priceHistory.length > 1 && t.price > t.priceHistory[t.priceHistory.length - 2]).length;
    const correlationFactor = Math.abs((upMoves / tokens.length) - 0.5) * 2; 

    let status: MarketRegime['status'] = 'NEUTRAL';
    if (avgVol > 0.015) status = 'VOLATILE'; 
    else if (correlationFactor > 0.6 && upMoves > tokens.length / 2) status = 'BULLISH';
    else if (correlationFactor > 0.6 && upMoves < tokens.length / 2) status = 'BEARISH';

    this.marketRegime.set({
      status,
      volatility: avgVol,
      correlation: correlationFactor
    });
  }
}

import { Injectable, inject, signal, effect } from '@angular/core';
import { TokenStateService } from './token-state.service';
import { Signal, SignalType, PerformanceData } from './types';

interface PendingSignal {
    signal: Signal;
    entryPrice: number;
    startTick: number;
}

@Injectable({
  providedIn: 'root'
})
export class PerformanceTrackerService {
    private tokenState = inject(TokenStateService);

    readonly stats = signal<Map<SignalType, PerformanceData>>(new Map());

    private pendingSignals = new Map<string, PendingSignal>();
    private processedSignalIds = new Set<string>();
    private tickCounter = 0;
    private readonly RESOLUTION_TICKS = 5; // Resolve after 5 ticks

    constructor() {
        effect(() => {
            this.tokenState.tokens(); // Depend on tokens to trigger effect on each data update
            this.tickCounter++;

            // It's important to process new signals *before* resolving old ones
            // to correctly capture the entry price on the tick the signal appeared.
            this.processNewSignals(this.tokenState.activeSignals());
            this.resolvePendingSignals();
        });
    }

    private processNewSignals(signals: Signal[]): void {
        const trackableSignals = signals.filter(s => this.isTrackable(s));

        for (const signal of trackableSignals) {
            if (!this.processedSignalIds.has(signal.id)) {
                const token = this.tokenState.tokens().find(t => t.symbol === signal.tokenSymbol);
                if (token) {
                    this.pendingSignals.set(signal.id, {
                        signal,
                        entryPrice: token.price,
                        startTick: this.tickCounter
                    });
                    this.processedSignalIds.add(signal.id);
                }
            }
        }
    }

    private resolvePendingSignals(): void {
        if (this.pendingSignals.size === 0) return;

        for (const [id, pending] of this.pendingSignals.entries()) {
            if (this.tickCounter >= pending.startTick + this.RESOLUTION_TICKS) {
                const token = this.tokenState.tokens().find(t => t.symbol === pending.signal.tokenSymbol);
                if (token) {
                    this.calculateOutcome(pending, token.price);
                    this.pendingSignals.delete(id);
                }
            }
        }
    }

    private calculateOutcome(pending: PendingSignal, exitPrice: number): void {
        const { signal, entryPrice } = pending;
        if (entryPrice === 0) return; // Avoid division by zero

        const returnPercent = ((exitPrice - entryPrice) / entryPrice) * 100;

        // For this simulation, all trackable signals are 'success' oriented, meaning they predict a price increase.
        const isWin = returnPercent > 0.05; // Consider it a win only if it's a meaningful gain (>0.05%)

        this.stats.update(currentStats => {
            const newStats = new Map(currentStats);
            // FIX: Correctly initialize 'existing' with a default PerformanceData object using getInitialData() to prevent type errors when a signal type is first encountered.
            const existing = newStats.get(signal.type) ?? this.getInitialData();

            const wins = existing.wins + (isWin ? 1 : 0);
            const losses = existing.losses + (isWin ? 0 : 1);
            const totalSignals = existing.totalSignals + 1;
            const totalPnlPercent = existing.totalPnlPercent + returnPercent;

            const updatedData: PerformanceData = {
                totalSignals,
                wins,
                losses,
                winRate: (wins / totalSignals) * 100,
                totalPnlPercent,
                averageReturn: totalPnlPercent / totalSignals,
            };

            newStats.set(signal.type, updatedData);
            return newStats;
        });
    }

    resetStats(): void {
        this.stats.set(new Map());
        this.pendingSignals.clear();
        this.processedSignalIds.clear();
        console.log('AXIOM: Performance audit data has been reset.');
    }

    private isTrackable(signal: Signal): boolean {
        const trackableTypes = [
            SignalType.BURST_HUNTER,
            SignalType.SUPPORT_BOUNCE,
            SignalType.JERRY_REVERSION,
            SignalType.VOLATILITY_SQUEEZE,
            SignalType.TREND_VECTOR,
        ];
        // For TREND_VECTOR, only track 'UP' predictions.
        if (signal.type === SignalType.TREND_VECTOR && signal.severity === 'danger') {
            return false;
        }
        return trackableTypes.includes(signal.type);
    }

    private getInitialData(): PerformanceData {
        return { totalSignals: 0, wins: 0, losses: 0, winRate: 0, totalPnlPercent: 0, averageReturn: 0 };
    }
}

