import { Injectable } from '@angular/core';
import { GoogleGenAI } from "@google/genai";
import { Token, MarketRegime, Signal } from './types';
import { AiTone } from './user-prefs.service';
import { MathUtils } from './math-utils';

@Injectable({
  providedIn: 'root'
})
export class GeminiService {
  private ai: GoogleGenAI | null = null;
  private isAvailable = false;

  constructor() {
    const key = process.env['API_KEY'];
    if (key) {
      this.ai = new GoogleGenAI({ apiKey: key });
      this.isAvailable = true;
    } else {
      console.warn('CYGNUS: API_KEY not found. AI features disabled.');
    }
  }

  async generateMarketNarrative(tokens: Token[], regime: MarketRegime, signals: Signal[], tone: AiTone): Promise<string> {
    if (!this.isAvailable || !this.ai) {
      return "AI MODULE OFFLINE. KEY MISSING.";
    }

    const tokenSummary = tokens.map(t => 
      `${t.symbol}: $${t.price.toFixed(4)}`
    ).join(', ');

    const signalSummary = signals.slice(0, 5).map(s => 
      `[${s.type}] ${s.tokenSymbol}: ${s.message}`
    ).join('; ');

    let styleInstruction = "";
    if (tone === 'CALM') {
      styleInstruction = "Style: Analytical, Reassuring, Clear, Objectively Optimistic. Avoid alarmist, urgent, or 'hype' language. Focus on structural clarity.";
    } else {
      styleInstruction = "Style: Cyberpunk, Concise, Analytical. High clarity.";
    }

    const prompt = `
      You are Project Cygnus, a crypto market intelligence system.
      Market Regime: ${regime.status} (Vol: ${regime.volatility.toFixed(2)}).
      Snapshot: ${tokenSummary}.
      Active Signals: ${signalSummary}.

      Generate a concise, 2-sentence market narrative. 
      ${styleInstruction}
      Do not use markdown. Just plain text.
    `;

    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-2.5-flash',
        contents: prompt,
      });
      return response.text || "NO NARRATIVE GENERATED";
    } catch (e) {
      console.error('Gemini Error', e);
      return "SYSTEM ERROR: AI UNREACHABLE";
    }
  }

  // NEW: Analyze specific signal context
  async analyzeSignalContext(signal: Signal, token: Token): Promise<string> {
    if (!this.isAvailable || !this.ai) return "AI OFFLINE";

    // Format volume history for context
    const recentVolumes = token.volumeHistory.slice(-20).map(v => Math.round(v)).join(', ');

    const prompt = `
      Analyze this specific trading signal for ${token.symbol}.
      Signal Type: ${signal.type}
      Message: ${signal.message}
      Confidence Score: ${signal.confidence}/100

      Context:
      Price: ${token.price}
      RSI (14): ${this.getRSI(token.priceHistory)}
      Current Volume: ${token.volume}
      Volume History (Last 20 periods): [${recentVolumes}]

      Provide a tactical, 1-sentence prediction or recommendation. 
      Is this a false positive or a valid move? 
      Keep it under 20 words. 
      Style: Military/Terminal.
    `;

    try {
       const response = await this.ai.models.generateContent({
        model: 'gemini-2.5-flash',
        contents: prompt,
      });
      return response.text || "ANALYSIS FAILED";
    } catch (e) {
      return "AI ERROR";
    }
  }

  private getRSI(history: number[]): string {
    const rsi = MathUtils.rsi(history, 14);
    return rsi ? rsi.toFixed(2) : "N/A"; 
  }
}

