              (dragstart)="onDragStart($event, token.symbol)"
              (dragend)="onDragEnd($event)"
              (dragover)="onDragOver($event)"
              (drop)="onDrop($event, token.symbol)"
              (dragenter)="onDragEnter($event)"
              (dragleave)="onDragLeave($event)"
