  private simulationDataSource = inject(SimulationDataSource);
  private liveDataSource = inject(LiveDataSource);
  private tokens: Token[] = [];
  private readonly updateInterval = 1000;  // 1 second
  private isUpdating = signal(false);
  private updateSubscription: Subscription | null = null;
  private coinGeckoEndpoint = 'https://api.coingecko.com/api/v3/coins/markets';
  private searchSubject = new Subject<string>();
  searchResult = signal<Token[]>([]);


  constructor() {
    effect(() => {
      this.prefs.dataSourceMode();
      this.startUpdates();
    });
  }

  ngOnDestroy(): void {
    this.stopUpdates();
  }

  private startUpdates(): void {
    this.stopUpdates(); // Stop any existing subscriptions
    this.updateSubscription = interval(this.updateInterval)
      .pipe(
        switchMap(() => this.performUpdate()),
        catchError(error => {
          console.error('Error during data update:', error);
          // Optionally, handle the error (e.g., show a notification)
          return of(null); // Continue the observable
        })
      )
      .subscribe();
  }

  private stopUpdates(): void {
    if (this.updateSubscription) {
      this.updateSubscription.unsubscribe();
      this.updateSubscription = null;
    }
  }

  // Y-Junction logic - central update function.
  private async performUpdate(): Promise<void> {
    this.isUpdating.set(true);
    const mode = this.prefs.dataSourceMode();
    let updatedTokens: Token[] = [];

    switch (mode) {
      case 'SIMULATION':
        updatedTokens = this.simulationDataSource.updateTokens(this.tokens);
        this.tokens = updatedTokens;
        break;
      case 'LIVE':
        updatedTokens = await this.liveDataSource.updateTokens(this.tokens);
        this.tokens = updatedTokens;
        break;
      case 'CUSTOM':
        const url = this.prefs.customApiUrl();
        updatedTokens = await this.liveDataSource.updateTokens(this.tokens, url);
        this.tokens = updatedTokens;
        break;
    }
    this.stateService.updateTokens(this.tokens);
    setTimeout(() => this.isUpdating.set(false), 500);
  }

  public addToken(symbol: string): void {
    const newToken: TokenDefinition = { symbol, price: 0, volume: 1000000, liquidityDepth: 5000000, };
    this.tokens = [...this.tokens, this.createToken(newToken)];
    this.stateService.updateTokens(this.tokens);
  }



