      this.configureHeartbeat(mode, rate);
    });
  }

  private initializeWatchlist() {
    const savedOrder = this.prefs.watchlistOrder();
    const symbolsToLoad = savedOrder.length > 0 ? savedOrder : DEFAULT_WATCHLIST;

    symbolsToLoad.forEach(symbol => {
      const dbToken = SOLANA_TOKEN_DB.find(t => t.symbol === symbol);
      if (dbToken) {
        this.addToken(dbToken.symbol, dbToken.cgId, dbToken.name, dbToken.imageUrl, false);
      }
    });
    this.stateService.updateTokens([...this.tokens]);
  }

  // --- PUBLIC API ---

  async searchTokens(query: string): Promise<TokenDefinition[]> {
    const q = query.toUpperCase().trim();
    if (!q) return [];

    const localMatches = SOLANA_TOKEN_DB.filter(t => 
      t.symbol.includes(q) || t.name.toUpperCase().includes(q)
    );

    if (this.prefs.dataSourceMode() === 'SIMULATION' || this.prefs.dataSourceMode() === 'CUSTOM') {
      return localMatches;
    }

    return this.liveDataSource.searchTokens(query, localMatches);
  }

  addToken(symbol: string, cgId?: string, name?: string, imageUrl?: string, save = true) {
    const s = symbol.toUpperCase().trim();
    if (!s || this.tokens.find(t => t.symbol === s)) return;

    const dbToken = SOLANA_TOKEN_DB.find(t => t.symbol === s);
    const finalCgId = cgId || dbToken?.cgId;
    const finalName = name || dbToken?.name || `${s} (Custom)`;
    const finalImageUrl = imageUrl || dbToken?.imageUrl;

    let startPrice = dbToken?.price || 0;

    if (!dbToken && !cgId && this.prefs.dataSourceMode() === 'SIMULATION') {
      startPrice = Math.random() * 10 + 0.1;
    }

    const newToken = this.createToken(
      s, finalName, startPrice, 
      startPrice > 0 ? startPrice * 0.95 : 0, 0, finalCgId, finalImageUrl
    );

    this.fillTokenHistory(newToken);
    this.tokens.push(newToken);
    this.stateService.updateTokens([...this.tokens]);

    if (save) {
      this.saveWatchlistOrder();
    }

    if (this.prefs.dataSourceMode() !== 'SIMULATION') {
      this.performUpdate();
    }
  }

  removeToken(symbol: string) {
    this.tokens = this.tokens.filter(t => t.symbol !== symbol);
    this.stateService.updateTokens([...this.tokens]);
    this.saveWatchlistOrder();
  }

  reorderTokens(fromSymbol: string, toSymbol: string) {
    const fromIndex = this.tokens.findIndex(t => t.symbol === fromSymbol);
    const toIndex = this.tokens.findIndex(t => t.symbol === toSymbol);

    if (fromIndex === -1 || toIndex === -1) return;

    const [movedToken] = this.tokens.splice(fromIndex, 1);
    this.tokens.splice(toIndex, 0, movedToken);

    this.stateService.updateTokens([...this.tokens]);
    this.saveWatchlistOrder();
  }

  private saveWatchlistOrder() {
    const symbols = this.tokens.map(t => t.symbol);
    this.prefs.saveWatchlistOrder(symbols);
  }

  // --- HEARTBEAT ENGINE ---

  private configureHeartbeat(mode: DataSourceMode, rate: RefreshRate) {
    if (this.timerId) clearInterval(this.timerId);

    let ms = 5000;
    if (mode === 'LIVE' || mode === 'CUSTOM') {
      switch (rate) {
        case 'AGGRESSIVE': ms = 30000; break;
        case 'STANDARD': ms = 60000; break;
        case 'SAFE': ms = 120000; break;
      }
    }

    this.duration = ms;
    this.currentDuration.set(this.duration);
    this.startTime = Date.now();

    this.performUpdate();

    this.timerId = setInterval(() => {
      const elapsed = Date.now() - this.startTime;
      if (elapsed >= this.duration) {
        this.performUpdate();
        this.startTime = Date.now();
        this.timerProgress.set(0);
      } else {
        this.timerProgress.set((elapsed / this.duration) * 100);
      }
    }, 100);
  }

  private async performUpdate() {
    this.isUpdating.set(true);

    const mode = this.prefs.dataSourceMode();
    let updatedTokens: Token[] = this.tokens;

    switch(mode) {
      case 'SIMULATION':
        updatedTokens = this.simulationDataSource.updateTokens(this.tokens);
        break;
      case 'LIVE':
        updatedTokens = await this.liveDataSource.updateTokens(this.tokens);
        break;
      case 'CUSTOM':
        const url = this.prefs.customApiUrl();
        if (url) {
            updatedTokens = await this.liveDataSource.updateTokens(this.tokens, url);
        }
        break;
    }

    this.tokens = updatedTokens;
    this.stateService.updateTokens(this.tokens);

    setTimeout(() => this.isUpdating.set(false), 500);
  }

  // --- DATA HELPERS ---

  private createToken(symbol: string, name: string, price: number, entry: number, apy: number, cgId?: string, imageUrl?: string): Token {
    return {
      symbol, name, price,
      entryPrice: entry,
      volume: 1000000 + Math.random() * 5000000,
      yield: apy,
      priceHistory: [],
      volumeHistory: [],
      liquidityDepth: 5000000 + Math.random() * 5000000,
      cgId, imageUrl
    };
  }

  private fillTokenHistory(token: Token) {
    let currentPrice = token.price || 1; 
    let currentVol = token.volume;
    for (let i = 0; i < 60; i++) {
      const change = (Math.random() - 0.5) * 0.02;
      currentPrice *= (1 - change);
      currentVol *= (0.8 + Math.random() * 0.4);
      token.priceHistory.unshift(currentPrice);
      token.volumeHistory.unshift(currentVol);
    }
  }

  ngOnDestroy() {
    if (this.timerId) clearInterval(this.timerId);
  }
}

import { Injectable, inject, signal, effect } from '@angular/core';
import { TokenStateService } from './token-state.service';
import { Signal, SignalType, PerformanceData } from './types';

interface PendingSignal {
    signal: Signal;
    entryPrice: number;
    startTick: number;
}

@Injectable({
  providedIn: 'root'
})
export class PerformanceTrackerService {
    private tokenState = inject(TokenStateService);

    readonly stats = signal<Map<SignalType, PerformanceData>>(new Map());

    private pendingSignals = new Map<string, PendingSignal>();
    private processedSignalIds = new Set<string>();
    private tickCounter = 0;
    private readonly RESOLUTION_TICKS = 5; // Resolve after 5 ticks

    constructor() {
        effect(() => {
            this.tokenState.tokens(); // Depend on tokens to trigger effect on each data update
            this.tickCounter++;

            // It's important to process new signals *before* resolving old ones
            // to correctly capture the entry price on the tick the signal appeared.
            this.processNewSignals(this.tokenState.activeSignals());
            this.resolvePendingSignals();
        });
    }

    private processNewSignals(signals: Signal[]): void {
        const trackableSignals = signals.filter(s => this.isTrackable(s));

        for (const signal of trackableSignals) {
            if (!this.processedSignalIds.has(signal.id)) {
                const token = this.tokenState.tokens().find(t => t.symbol === signal.tokenSymbol);
                if (token) {
                    this.pendingSignals.set(signal.id, {
                        signal,
                        entryPrice: token.price,
                        startTick: this.tickCounter
                    });
                    this.processedSignalIds.add(signal.id);
                }
            }
        }
    }

    private resolvePendingSignals(): void {
        if (this.pendingSignals.size === 0) return;

        for (const [id, pending] of this.pendingSignals.entries()) {
            if (this.tickCounter >= pending.startTick + this.RESOLUTION_TICKS) {
                const token = this.tokenState.tokens().find(t => t.symbol === pending.signal.tokenSymbol);
                if (token) {
                    this.calculateOutcome(pending, token.price);
                    this.pendingSignals.delete(id);
                }
            }
        }
    }

    private calculateOutcome(pending: PendingSignal, exitPrice: number): void {
        const { signal, entryPrice } = pending;
        if (entryPrice === 0) return; // Avoid division by zero

        const returnPercent = ((exitPrice - entryPrice) / entryPrice) * 100;

        // For this simulation, all trackable signals are 'success' oriented, meaning they predict a price increase.
        const isWin = returnPercent > 0.05; // Consider it a win only if it's a meaningful gain (>0.05%)

        this.stats.update(currentStats => {
            const newStats = new Map(currentStats);

            // FIX: The `existing` variable was being inferred as `unknown`. Explicitly typing
            // it as `PerformanceData` allows safe access to its properties.
            const existing: PerformanceData = newStats.get(signal.type) || this.getInitialData();

            const wins = existing.wins + (isWin ? 1 : 0);
            const losses = existing.losses + (isWin ? 0 : 1);
            const totalSignals = existing.totalSignals + 1;
            const totalPnlPercent = existing.totalPnlPercent + returnPercent;

            const updatedData: PerformanceData = {
                totalSignals,
                wins,
                losses,
                winRate: (wins / totalSignals) * 100,
                totalPnlPercent,
                averageReturn: totalPnlPercent / totalSignals,
            };

            newStats.set(signal.type, updatedData);
            return newStats;
        });
    }

    resetStats(): void {
        this.stats.set(new Map());
        this.pendingSignals.clear();
        this.processedSignalIds.clear();
        console.log('CYGNUS: Performance audit data has been reset.');
    }

    private isTrackable(signal: Signal): boolean {
        const trackableTypes = [
            SignalType.BURST_HUNTER,
            SignalType.SUPPORT_BOUNCE,
            SignalType.JERRY_REVERSION,
            SignalType.VOLATILITY_SQUEEZE,
            SignalType.TREND_VECTOR,
        ];
        // For TREND_VECTOR, only track 'UP' predictions.
        if (signal.type === SignalType.TREND_VECTOR && signal.severity === 'danger') {
            return false;
        }
        return trackableTypes.includes(signal.type);
    }

    private getInitialData(): PerformanceData {
        return { totalSignals: 0, wins: 0, losses: 0, winRate: 0, totalPnlPercent: 0, averageReturn: 0 };
    }
}

export interface Token {
  symbol: string;
  name: string;
  price: number;
  entryPrice: number; // For Gain Lock-100
  volume: number;
  yield: number; // APY for Stable Anchor
  priceHistory: number[]; // For SMAs, RSI, Volatility
  volumeHistory: number[]; // For Burst Hunter
