        // For this simulation, all trackable signals are 'success' oriented, meaning they predict a price increase.
        const isWin = returnPercent > 0.05; // Consider it a win only if it's a meaningful gain (>0.05%)

        this.stats.update(currentStats => {
            const newStats = new Map(currentStats);

            // FIX: Use `getInitialData()` to provide a valid default when no performance data exists
            // for a signal type, preventing an error from an invalid empty object `{}` initializer.
            const existing = newStats.get(signal.type) || this.getInitialData();

            const wins = existing.wins + (isWin ? 1 : 0);
            const losses = existing.losses + (isWin ? 0 : 1);
            const totalSignals = existing.totalSignals + 1;
            const totalPnlPercent = existing.totalPnlPercent + returnPercent;

            const updatedData: PerformanceData = {
                totalSignals,
                wins,
                losses,
                winRate: (wins / totalSignals) * 100,
                totalPnlPercent,
                averageReturn: totalPnlPercent / totalSignals,
            };

            newStats.set(signal.type, updatedData);
            return newStats;
        });
    }

    resetStats(): void {
        this.stats.set(new Map());
        this.pendingSignals.clear();
        this.processedSignalIds.clear();
        console.log('CYGNUS: Performance audit data has been reset.');
    }

    private isTrackable(signal: Signal): boolean {
        const trackableTypes = [
            SignalType.BURST_HUNTER,
            SignalType.SUPPORT_BOUNCE,
            SignalType.JERRY_REVERSION,
            SignalType.VOLATILITY_SQUEEZE,
            SignalType.TREND_VECTOR,
        ];
        // For TREND_VECTOR, only track 'UP' predictions.
        if (signal.type === SignalType.TREND_VECTOR && signal.severity === 'danger') {
            return false;
        }
        return trackableTypes.includes(signal.type);
    }

    private getInitialData(): PerformanceData {
        return { totalSignals: 0, wins: 0, losses: 0, winRate: 0, totalPnlPercent: 0, averageReturn: 0 };
    }
}

export interface Token {
  symbol: string;
  name: string;
  price: number;
  entryPrice: number; // For Gain Lock-100
  volume: number;
  yield: number; // APY for Stable Anchor
  priceHistory: number[]; // For SMAs, RSI, Volatility
  volumeHistory: number[]; // For Burst Hunter
  liquidityDepth: number; // For Venue Shield
  cgId?: string; // CoinGecko ID
  imageUrl?: string; // Token icon URL
}

export enum SignalType {
  BURST_HUNTER = 'BURST_HUNTER', // Conviction
  GAIN_LOCK = 'GAIN_LOCK', // Risk Mgmt
  HYPE_PULSE_BUY = 'HYPE_PULSE_BUY', // Momentum
  HYPE_PULSE_SELL = 'HYPE_PULSE_SELL',
  STABLE_ANCHOR = 'STABLE_ANCHOR', // Capital Preservation
  VENUE_SHIELD = 'VENUE_SHIELD', // Execution
  TREND_VECTOR = 'TREND_VECTOR', // Linear Regression Prediction
  SUPPORT_BOUNCE = 'SUPPORT_BOUNCE', // Geometric/Candle Patterns
  VOLATILITY_SQUEEZE = 'VOLATILITY_SQUEEZE', // Bollinger Squeeze (Prediction)
  PRICE_ALERT = 'PRICE_ALERT', // User-defined price alert
  JERRY_REVERSION = 'JERRY_REVERSION', // Systematic Mean Reversion
  NEWS_SPIKE = 'NEWS_SPIKE' // AI-driven News Event
}

export interface Signal {
  id: string;
  timestamp: number;
  type: SignalType;
  tokenSymbol: string;
  message: string;
  severity: 'info' | 'success' | 'warning' | 'danger';
  confidence: number; // 0 to 100
  aiAnalysis?: string; // Populated on demand
  isAnalyzing?: boolean; // UI state
  meta?: any; // For extra data like projected price
}

export interface MarketRegime {
  status: 'BULLISH' | 'BEARISH' | 'NEUTRAL' | 'VOLATILE';
  volatility: number;
  correlation: number;
}

export interface PriceAlert {
  targetPrice: number;
  condition: 'ABOVE' | 'BELOW';
}

export interface PerformanceData {
  totalSignals: number;
  wins: number;
  losses: number;
  winRate: number; // as a percentage
  totalPnlPercent: number;
  averageReturn: number; // as a percentage
}

export interface GroundingChunk {
  web: {
    uri: string;
    title: string;
  };
}

import { Injectable } from '@angular/core';
import { GoogleGenAI, GenerateContentConfig, Type } from "@google/genai";
import { Token, MarketRegime, Signal, GroundingChunk } from './types';
import { AiTone } from './user-prefs.service';
import { MathUtils } from './math-utils';

interface NewsSpikeResponse {
  isSignificantNews: boolean;
  articleTitle?: string;
  articleUrl?: string;
}

@Injectable({
  providedIn: 'root'
})
export class GeminiService {
  private ai: GoogleGenAI | null = null;
  private isAvailable = false;

  constructor() {
    const key = process.env['API_KEY'];
    if (key) {
      this.ai = new GoogleGenAI({ apiKey: key });
      this.isAvailable = true;
    } else {
      console.warn('CYGNUS: API_KEY not found. AI features disabled.');
    }
  }

  async generateMarketNarrative(
    tokens: Token[], 
    regime: MarketRegime, 
    signals: Signal[], 
    tone: AiTone, 
    useGrounding: boolean
  ): Promise<{ narrative: string; sources: GroundingChunk[] }> {
    const defaultResponse = { narrative: "AI MODULE OFFLINE. KEY MISSING.", sources: [] };
    if (!this.isAvailable || !this.ai) {
      return defaultResponse;
    }

    const tokenSummary = tokens.map(t => 
      `${t.symbol}: $${t.price.toFixed(4)}`
    ).join(', ');

    const signalSummary = signals.slice(0, 5).map(s => 
      `[${s.type}] ${s.tokenSymbol}: ${s.message}`
    ).join('; ');

    let styleInstruction = "";
    if (tone === 'CALM') {
      styleInstruction = "Style: Analytical, Reassuring, Clear, Objectively Optimistic. Avoid alarmist, urgent, or 'hype' language. Focus on structural clarity.";
    } else {
      styleInstruction = "Style: Cyberpunk, Concise, Analytical. High clarity.";
    }

    const prompt = `
      You are Project Cygnus, a crypto market intelligence system.
      Market Regime: ${regime.status} (Vol: ${regime.volatility.toFixed(2)}).
      Snapshot: ${tokenSummary}.
      Active Signals: ${signalSummary}.

      Generate a concise, 2-sentence market narrative. If recent news is relevant, incorporate it.
      ${styleInstruction}
      Do not use markdown. Just plain text.
    `;

    const config: GenerateContentConfig = {};
    if (useGrounding) {
      config.tools = [{googleSearch: {}}];
    }

    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-2.5-flash',
        contents: prompt,
        config: config
      });

      const narrative = response.text || "NO NARRATIVE GENERATED";
      const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
      const sources: GroundingChunk[] = (Array.isArray(groundingChunks) ? groundingChunks : []) as GroundingChunk[];

      return { narrative, sources };
    } catch (e) {
      console.error('Gemini Error', e);
      return { narrative: "SYSTEM ERROR: AI UNREACHABLE", sources: [] };
    }
  }

  async checkForNewsSpike(token: Token): Promise<NewsSpikeResponse | null> {
    if (!this.isAvailable || !this.ai) return null;

    const prompt = `
      Search for significant news in the last 24 hours for the cryptocurrency '${token.name} (${token.symbol})'.
      'Significant news' includes major partnerships, CEX listings, protocol upgrades, security vulnerabilities, or major regulatory actions.
      If you find such news, provide the article title and URL.
    `;

    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-2.5-flash',
        contents: prompt,
        config: {
          tools: [{googleSearch: {}}],
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              isSignificantNews: { type: Type.BOOLEAN },
              articleTitle: { type: Type.STRING },
              articleUrl: { type: Type.STRING }
            }
          }
        }
      });

      const jsonText = response.text?.trim();
      if (jsonText) {
        return JSON.parse(jsonText) as NewsSpikeResponse;
      }
      return null;
    } catch (e) {
      console.error(`News Spike check failed for ${token.symbol}`, e);
      return null;
    }
  }

  // NEW: Analyze specific signal context
  async analyzeSignalContext(signal: Signal, token: Token): Promise<string> {
    if (!this.isAvailable || !this.ai) return "AI OFFLINE";

    // Format volume history for context
    const recentVolumes = token.volumeHistory.slice(-20).map(v => Math.round(v)).join(', ');

    const prompt = `
      Analyze this specific trading signal for ${token.symbol}.
      Signal Type: ${signal.type}
      Message: ${signal.message}
      Confidence Score: ${signal.confidence}/100

      Context:
      Price: ${token.price}
      RSI (14): ${this.getRSI(token.priceHistory)}
      Current Volume: ${token.volume}
      Volume History (Last 20 periods): [${recentVolumes}]

      Provide a tactical, 1-sentence prediction or recommendation. 
      Is this a false positive or a valid move? 
      Keep it under 20 words. 
      Style: Military/Terminal.
    `;

    try {
       const response = await this.ai.models.generateContent({
        model: 'gemini-2.5-flash',
        contents: prompt,
      });
      return response.text || "ANALYSIS FAILED";
    } catch (e) {
      return "AI ERROR";
    }
  }

  private getRSI(history: number[]): string {
    const rsi = MathUtils.rsi(history, 14);
    return rsi ? rsi.toFixed(2) : "N/A"; 
  }
}

import { Injectable, signal, computed, inject } from '@angular/core';
import { Token, Signal, SignalType, MarketRegime, PriceAlert } from './types';
import { MathUtils } from './math-utils';
import { GeminiService } from './gemini.service';
import * as d3 from 'd3';

@Injectable({
  providedIn: 'root'
})
export class TokenStateService {
  private geminiService = inject(GeminiService);

  // State
  readonly tokens = signal<Token[]>([]);
  readonly marketRegime = signal<MarketRegime>({ status: 'NEUTRAL', volatility: 0, correlation: 0 });
  readonly selectedTokenSymbol = signal<string | null>(null);
  readonly priceAlerts = signal<Map<string, PriceAlert>>(new Map());

  // --- Signal Generation Engine ---
  // Signals derived from pure, synchronous calculations.
  private readonly syncSignals = computed(() => {
    const currentTokens = this.tokens();
    let allSignals: Signal[] = [];
    currentTokens.forEach(token => {
      const tokenSignals = [
        this._generatePriceAlertSignal(token),
        this._generateBurstHunterSignal(token),
        this._generateGainLockSignal(token),
        this._generateHypePulseSignal(token),
        this._generateTrendVectorSignal(token),
        this._generateStableAnchorSignal(token),
        this._generateVenueShieldSignal(token),
        this._generateSupportBounceSignal(token),
        this._generateVolatilitySqueezeSignal(token),
        this._generateJerryReversionSignal(token)
      ].filter((s): s is Signal => s !== null);
      allSignals.push(...tokenSignals);
    });
    return allSignals;
  });

  // Signals derived from asynchronous, API-driven sources (e.g., AI analysis).
  private readonly asyncSignals = signal<Signal[]>([]);

  // The final, merged list of all signals available to the UI.
  readonly activeSignals = computed(() => {
    const all = [...this.syncSignals(), ...this.asyncSignals()];
    return all.sort((a, b) => b.timestamp - a.timestamp);
  });

  // --- END Signal Generation Engine ---

  readonly filteredSignals = computed(() => {
    const signals = this.activeSignals();
    const selected = this.selectedTokenSymbol();
    if (!selected) return signals;
    return signals.filter(s => s.tokenSymbol === selected);
  });

  readonly marketSummary = computed(() => {
    const summary = { advancing: 0, declining: 0, unchanged: 0 };
    this.tokens().forEach(token => {
        if (token.priceHistory.length < 2) {
            summary.unchanged++;
            return;
        }
        const currentPrice = token.price;
        const prevPrice = token.priceHistory[token.priceHistory.length - 2];
        if (currentPrice > prevPrice) summary.advancing++;
        else if (currentPrice < prevPrice) summary.declining++;
        else summary.unchanged++;
    });
    return summary;
  });

  // Action: Update State
  updateTokens(newTokens: Token[]) {
    this.tokens.set(newTokens);
    this.updateRegime(newTokens);
  }

  toggleSelectedToken(symbol: string) {
    this.selectedTokenSymbol.update(current => current === symbol ? null : symbol);
  }

  clearSelection() {
    this.selectedTokenSymbol.set(null);
  }

  // --- Price Alert Actions ---
  setPriceAlert(symbol: string, targetPrice: number, condition: 'ABOVE' | 'BELOW') {
    if (!targetPrice || targetPrice <= 0) {
      this.removePriceAlert(symbol);
      return;
    }
    this.priceAlerts.update(alerts => {
      const newAlerts = new Map(alerts);
      newAlerts.set(symbol, { targetPrice, condition });
      return newAlerts;
    });
  }

  removePriceAlert(symbol: string) {
    this.priceAlerts.update(alerts => {
      const newAlerts = new Map(alerts);
      newAlerts.delete(symbol);
      return newAlerts;
    });
  }

  // --- Async Signal Trigger ---
  async triggerAsyncSignalGeneration() {
    const currentTokens = this.tokens();
    if (currentTokens.length === 0) return;

    const newsSpikeChecks = currentTokens.map(async (token) => {
      const result = await this.geminiService.checkForNewsSpike(token);
      if (result?.isSignificantNews && result.articleTitle) {
        return this._generateNewsSpikeSignal(token, result.articleTitle, result.articleUrl);
      }
      return null;
    });

    const newSignals = (await Promise.all(newsSpikeChecks)).filter((s): s is Signal => s !== null);
    this.asyncSignals.set(newSignals);
  }

  private updateRegime(tokens: Token[]) {
    if (tokens.length === 0) return;
    const avgVol = tokens.reduce((acc, t) => {
        const history = t.priceHistory.slice(-10);
        if (history.length === 0) return acc;
        const vol = MathUtils.stdDev(history) / MathUtils.average(history);
        return acc + vol;
    }, 0) / tokens.length;

    const upMoves = tokens.filter(t => t.priceHistory.length > 1 && t.price > t.priceHistory[t.priceHistory.length - 2]).length;
    const correlationFactor = Math.abs((upMoves / tokens.length) - 0.5) * 2; 

    let status: MarketRegime['status'] = 'NEUTRAL';
    if (avgVol > 0.015) status = 'VOLATILE'; 
    else if (correlationFactor > 0.6 && upMoves > tokens.length / 2) status = 'BULLISH';
    else if (correlationFactor > 0.6 && upMoves < tokens.length / 2) status = 'BEARISH';

    this.marketRegime.set({ status, volatility: avgVol, correlation: correlationFactor });
  }

  // --- Individual Algorithm Implementations ---

  private _generateNewsSpikeSignal(token: Token, title: string, url?: string): Signal | null {
    return {
      id: `NEWS_SPIKE:${token.symbol}:${Date.now()}`,
      timestamp: Date.now(),
      type: SignalType.NEWS_SPIKE,
      tokenSymbol: token.symbol,
      message: `NEWS: ${title}`,
      severity: 'warning',
      confidence: 95,
      meta: { url }
    };
  }

  private _generatePriceAlertSignal(token: Token): Signal | null {
    const alert = this.priceAlerts().get(token.symbol);
    if (!alert) return null;

    const conditionMet = 
      (alert.condition === 'ABOVE' && token.price > alert.targetPrice) ||
      (alert.condition === 'BELOW' && token.price < alert.targetPrice);

    if (conditionMet) {
      return {
        id: `PRICE_ALERT:${token.symbol}`,
        timestamp: Date.now(),
        type: SignalType.PRICE_ALERT,
        tokenSymbol: token.symbol,
        message: `Price crossed ${alert.condition.toLowerCase()} alert at $${alert.targetPrice.toFixed(4)}.`,
        severity: 'warning',
        confidence: 100 
      };
    }
    return null;
  }

  private _generateBurstHunterSignal(token: Token): Signal | null {
    const smaVol20 = MathUtils.sma(token.volumeHistory, 20);
    const sma20 = MathUtils.sma(token.priceHistory, 20);
    if (!smaVol20 || token.priceHistory.length < 3 || !sma20) return null;

    const lastPrice = token.priceHistory[token.priceHistory.length - 2];
    const prevLastPrice = token.priceHistory[token.priceHistory.length - 3];
    const priceChange = (token.price - lastPrice) / lastPrice;
    const prevPriceChange = (lastPrice - prevLastPrice) / prevLastPrice;
    const isAccelerating = priceChange > prevPriceChange;
    const ratio = token.volume / smaVol20;
    const inUptrend = token.price > sma20;

    if (ratio > 3.5 && priceChange > 0.02 && isAccelerating && inUptrend) {
      const marketSummary = this.marketSummary();
      let conf = Math.min(Math.round((ratio / 10) * 100), 85) + 5;
      const marketBreadth = marketSummary.advancing / (marketSummary.advancing + marketSummary.declining || 1);
      if (marketBreadth > 0.6) conf = Math.min(conf + 10, 99);

      return {
        id: `BURST:${token.symbol}`,
        timestamp: Date.now(),
        type: SignalType.BURST_HUNTER,
        tokenSymbol: token.symbol,
        message: `Macro-Confirmed Volume Burst: ${ratio.toFixed(1)}x normal.`,
        severity: 'success',
        confidence: conf
      };
    }
    return null;
  }

  private _generateGainLockSignal(token: Token): Signal | null {
    const profitMargin = (token.price - token.entryPrice) / token.entryPrice;
    const sma10 = MathUtils.sma(token.priceHistory, 10);
    const sma50 = MathUtils.sma(token.priceHistory, 50);

    if (profitMargin > 1.0 && sma10 && sma50 && sma10 < sma50) {
       return {
          id: `LOCK:${token.symbol}`,
          timestamp: Date.now(),
          type: SignalType.GAIN_LOCK,
          tokenSymbol: token.symbol,
          message: `Take Profit: +${(profitMargin * 100).toFixed(0)}% gain with Momentum Death Cross.`,
          severity: 'warning',
          confidence: 90 
        };
    }
    return null;
  }

  private _generateHypePulseSignal(token: Token): Signal | null {
    const rsi = MathUtils.rsi(token.priceHistory, 14);
    if (!rsi) return null;

    let overboughtThreshold = 70;
    const marketRegime = this.marketRegime();

    if (marketRegime.status === 'BULLISH') overboughtThreshold = 80;
    else if (marketRegime.status === 'BEARISH') overboughtThreshold = 60;

    if (rsi > overboughtThreshold) {
      const conf = Math.min(Math.round(((rsi - overboughtThreshold) / (100 - overboughtThreshold)) * 100) + 50, 95);
      return {
          id: `HYPE_BUY:${token.symbol}`,
          timestamp: Date.now(),
          type: SignalType.HYPE_PULSE_BUY,
          tokenSymbol: token.symbol,
          message: `Overbought (RSI > ${overboughtThreshold}): ${rsi.toFixed(0)}.`,
          severity: 'info',
          confidence: conf
      };
    }
    return null;
  }

  private _generateTrendVectorSignal(token: Token): Signal | null {
      const historyShort = token.priceHistory.slice(-15);
      const regression = MathUtils.linearRegression(historyShort);
      const sma50 = MathUtils.sma(token.priceHistory, 50);
      const currentVolatility = this.marketRegime().volatility;
      const rSquaredThreshold = currentVolatility > 0.015 ? 0.75 : 0.60;

      if (regression && sma50 && regression.r2 > rSquaredThreshold && currentVolatility < 0.025) {
        const slopePercent = regression.m / token.price;
        if (Math.abs(slopePercent) > 0.005) {
           const direction = slopePercent > 0 ? 'UP' : 'DOWN';
           const isConfirmed = (direction === 'UP' && token.price > sma50) || (direction === 'DOWN' && token.price < sma50);

           if (isConfirmed) {
              const projected = token.price + (regression.m * 5); 
              const conf = 85 + Math.round(((regression.r2 - rSquaredThreshold) / (1.0 - rSquaredThreshold)) * 14);
              return {
                id: `VECTOR:${token.symbol}`,
                timestamp: Date.now(),
                type: SignalType.TREND_VECTOR,
                tokenSymbol: token.symbol,
                message: `Strong Trend Vector (R²=${regression.r2.toFixed(2)}): Projecting ${projected.toFixed(2)}`,
                severity: direction === 'UP' ? 'success' : 'danger',
                confidence: Math.min(conf, 99),
                meta: { projectedPrice: projected }
              };
           }
        }
      }
      return null;
  }

  private _generateStableAnchorSignal(token: Token): Signal | null {
      const volatility = MathUtils.stdDev(token.priceHistory.slice(-20)) / token.price; 
      if (volatility < 0.05 && token.yield > 5.0) {
         return {
            id: `ANCHOR:${token.symbol}`,
            timestamp: Date.now(),
            type: SignalType.STABLE_ANCHOR,
            tokenSymbol: token.symbol,
            message: `Yield Safe Haven: ${token.yield.toFixed(2)}% APY.`,
            severity: 'success',
            confidence: 85
          };
      }
      return null;
  }

  private _generateVenueShieldSignal(token: Token): Signal | null {
      if (token.liquidityDepth < 1000000) { 
         return {
            id: `VENUE:${token.symbol}`,
            timestamp: Date.now(),
            type: SignalType.VENUE_SHIELD,
            tokenSymbol: token.symbol,
            message: `High Slippage Risk: Low Liquidity.`,
            severity: 'danger',
            confidence: 100
          };
      }
      return null;
  }

  private _generateSupportBounceSignal(token: Token): Signal | null {
      const rsi = MathUtils.rsi(token.priceHistory, 14);
      if (token.priceHistory.length > 20 && token.volumeHistory.length > 2 && rsi && rsi < 65) {
         const recent = token.priceHistory.slice(-20);
         const minPrice = d3.min(recent) || 0;
         const current = token.price;
         const prev = token.priceHistory[token.priceHistory.length - 2];
         const volumeConf = token.volume > token.volumeHistory[token.volumeHistory.length - 2];

         if (current > prev && (current - minPrice) / minPrice < 0.05 && current > minPrice && volumeConf) {
            return {
              id: `SUPPORT_BOUNCE:${token.symbol}`,
              timestamp: Date.now(),
              type: SignalType.SUPPORT_BOUNCE,
              tokenSymbol: token.symbol,
              message: `Volume-Confirmed Bounce off 20-period low.`,
              severity: 'success',
              confidence: 75
            };
         }
      }
      return null;
  }

  private _generateVolatilitySqueezeSignal(token: Token): Signal | null {
      const rsi = MathUtils.rsi(token.priceHistory, 14);
      const sma20 = MathUtils.sma(token.priceHistory, 20);
      if (token.priceHistory.length > 20 && rsi && rsi > 40 && rsi < 60) {
         const period = 20;
         const recent = token.priceHistory.slice(-period);
         const sma = sma20 || token.price;
         const stdDev = MathUtils.stdDev(recent);

         const upper = sma + (2 * stdDev);
         const lower = sma - (2 * stdDev);
         const bandwidth = (upper - lower) / sma;

         if (bandwidth < 0.025) {
            const conf = 80 + Math.round(((0.025 - bandwidth) / 0.025) * 19);
            return {
              id: `SQUEEZE:${token.symbol}`,
              timestamp: Date.now(),
              type: SignalType.VOLATILITY_SQUEEZE,
              tokenSymbol: token.symbol,
              message: `High-Compression Squeeze: (Bandwidth ${(bandwidth*100).toFixed(2)}%).`,
              severity: 'warning',
              confidence: Math.min(conf, 99)
            };
         }
      }
      return null;
  }

  private _generateJerryReversionSignal(token: Token): Signal | null {
    const marketRegime = this.marketRegime();
    if ((marketRegime.status === 'NEUTRAL' || marketRegime.status === 'VOLATILE') && token.priceHistory.length > 20) {
      const sma20 = MathUtils.sma(token.priceHistory, 20);
      const stdDev20 = MathUtils.stdDev(token.priceHistory.slice(-20));
      const prevPrice = token.priceHistory[token.priceHistory.length - 2];
      const prevPrevPrice = token.priceHistory[token.priceHistory.length - 3];

      if (sma20 && stdDev20 && prevPrice && prevPrevPrice) {
        const currentVolatility = stdDev20 / token.price;
        const priceDeviation = (sma20 - token.price) / sma20;
        const isBelowMean = priceDeviation > 0.05;
        const isLowVolatility = currentVolatility < 0.10;
        const isReverting = token.price > prevPrice && prevPrice > prevPrevPrice;

        if (isBelowMean && isLowVolatility && isReverting) {
          let conf = 75;
          if (priceDeviation > 0.1) conf += 10;
          if (currentVolatility < 0.05) conf += 10;

          return {
            id: `JERRY:${token.symbol}`,
            timestamp: Date.now(),
            type: SignalType.JERRY_REVERSION,
            tokenSymbol: token.symbol,
            message: `Confirmed Reversion: ${(priceDeviation * 100).toFixed(0)}% below mean.`,
            severity: 'success',
            confidence: Math.min(conf, 99)
          };
        }
      }
    }
    return null;
  }
}

